SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Match the following AC circuit parameters (Column-I) with their expressions (Column-II):\nColumn-I: (P) Impedance of LCR circuit (Q) Resonant frequency (R) Power factor (S) Q-factor\nColumn-II: (1) R/Z (2) √(R² + (X_L − X_C)²) (3) ω₀L/R (4) 1/(2π√(LC))", "explanation": "(P) Impedance Z = √(R² + (X_L − X_C)²) → (2). (Q) Resonant frequency f₀ = 1/(2π√(LC)) → (4). (R) Power factor cos φ = R/Z → (1). (S) Q-factor = ω₀L/R → (3).", "correct_answer": "B", "concept_tags": ["LCR-circuit", "matching", "formulas"], "payload": {"question_id": "cuet-phy-ac-adv-39", "subtopic": "AC circuit formulas", "topic_name": "AC Circuits — Advanced", "bloom_level": "remember", "options": [{"key": "A", "value": "P→1, Q→2, R→3, S→4", "is_correct": false}, {"key": "B", "value": "P→2, Q→4, R→1, S→3", "is_correct": true}, {"key": "C", "value": "P→2, Q→3, R→4, S→1", "is_correct": false}, {"key": "D", "value": "P→4, Q→2, R→3, S→1", "is_correct": false}], "elimination_hints": ["Impedance involves square root of R² plus reactance difference squared → (2).", "Resonant frequency has 1/(2π√(LC)) → (4).", "Power factor = cos φ = R/Z → (1); Q = ω₀L/R → (3)."]}}, {"chapter_id": "cuet-phy-em-induction", "topic_id": "cuet-phy-ac-advanced", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Assertion (A): At resonance in a series LCR circuit, the voltage across the inductor can be much greater than the applied voltage.\nReason (R): The Q-factor of the circuit amplifies the voltage across individual reactive components at resonance.", "explanation": "At resonance, V_L = IX_L = (V/R)(ω₀L) = V(ω₀L/R) = VQ. Since Q can be much greater than 1 (e.g., Q = 50), the voltage across L (or C) can be 50 times the applied voltage. This voltage amplification is the essence of the Q-factor. Both A and R are true, and R correctly explains A.", "correct_answer": "A", "concept_tags": ["resonance", "Q-factor", "voltage-amplification", "assertion-reason"], "payload": {"question_id": "cuet-phy-ac-adv-40", "subtopic": "Q-factor and sharpness of resonance", "topic_name": "AC Circuits — Advanced", "bloom_level": "evaluate", "options": [{"key": "A", "value": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "value": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "value": "A is true but R is false", "is_correct": false}, {"key": "D", "value": "A is false but R is true", "is_correct": false}], "elimination_hints": ["V_L = VQ at resonance, and Q can be >> 1, so V_L >> V. Assertion A is true.", "The Q-factor is precisely the ratio V_L/V (or V_C/V) at resonance. Reason R is true.", "R directly explains A — the voltage amplification is due to the Q-factor."]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is NOT an electromagnetic wave?", "explanation": "Ultrasound waves are mechanical (longitudinal) waves that require a material medium for propagation. They are pressure variations in air, water, or tissue. All the other options — X-rays, microwaves, and gamma rays — are electromagnetic waves that can travel through vacuum.", "correct_answer": "C", "concept_tags": ["em-wave-types", "mechanical-vs-em", "ultrasound"], "payload": {"question_id": "cuet-phy-emwave-21", "subtopic": "nature of electromagnetic waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "X-rays", "is_correct": false}, {"key": "B", "text": "Microwaves", "is_correct": false}, {"key": "C", "text": "Ultrasound waves", "is_correct": true}, {"key": "D", "text": "Gamma rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "X-rays are high-frequency electromagnetic waves used in medical imaging. They travel through vacuum.", "misconception": "Thinking X-rays need a medium"}, {"option_key": "B", "hint": "Microwaves are EM waves with wavelengths in the cm range, used in ovens and communication.", "misconception": "Confusing microwaves with sound waves"}, {"option_key": "D", "hint": "Gamma rays are the highest-frequency electromagnetic waves, emitted by radioactive nuclei.", "misconception": "Confusing nuclear radiation with mechanical waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Electromagnetic waves travel in vacuum with a speed of:", "explanation": "All electromagnetic waves travel in vacuum at the speed of light, c = 3 × 10⁸ m/s, regardless of their frequency or wavelength. This is a fundamental constant of nature derived from Maxwell''s equations: c = 1/√(μ₀ε₀).", "correct_answer": "B", "concept_tags": ["speed-of-light", "vacuum", "maxwell-equations"], "payload": {"question_id": "cuet-phy-emwave-22", "subtopic": "speed of electromagnetic waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "3 × 10⁶ m/s", "is_correct": false}, {"key": "B", "text": "3 × 10⁸ m/s", "is_correct": false}, {"key": "C", "text": "3 × 10¹⁰ m/s", "is_correct": false}, {"key": "D", "text": "Speed depends on wavelength", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "3 × 10⁶ m/s is 1000 times slower than light. This is roughly 1% of the speed of light.", "misconception": "Confusing order of magnitude"}, {"option_key": "C", "hint": "3 × 10¹⁰ m/s would exceed the speed of light, violating special relativity.", "misconception": "Exaggerating the speed of EM waves"}, {"option_key": "D", "hint": "In vacuum, all EM waves travel at the same speed c, regardless of wavelength. Speed depends on wavelength only in a dispersive medium.", "misconception": "Applying medium-dispersion properties to vacuum"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which electromagnetic waves are used in RADAR systems?", "explanation": "RADAR (Radio Detection And Ranging) uses microwaves, typically in the frequency range of 1–300 GHz. Microwaves are ideal because they can penetrate clouds, are reflected well by metallic objects, and can be focused into narrow beams using dish antennas.", "correct_answer": "C", "concept_tags": ["radar", "microwaves", "applications"], "payload": {"question_id": "cuet-phy-emwave-23", "subtopic": "applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Infrared waves", "is_correct": false}, {"key": "B", "text": "Ultraviolet rays", "is_correct": false}, {"key": "C", "text": "Microwaves", "is_correct": true}, {"key": "D", "text": "Gamma rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Infrared waves are used in remote controls, night vision, and thermal imaging — not in RADAR.", "misconception": "Confusing IR applications with RADAR"}, {"option_key": "B", "hint": "UV rays are absorbed by the atmosphere and are used in sterilisation, not for detection and ranging.", "misconception": "Mixing up UV applications"}, {"option_key": "D", "hint": "Gamma rays are extremely high-energy and penetrating — impractical and dangerous for detection systems.", "misconception": "Thinking higher energy means better detection"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The wavelength range of visible light is approximately:", "explanation": "Visible light spans roughly 400 nm (violet) to 700 nm (red). This narrow band of the electromagnetic spectrum is the only portion detectable by the human eye. Below 400 nm lies ultraviolet, and above 700 nm lies infrared.", "correct_answer": "B", "concept_tags": ["visible-light", "wavelength-range", "spectrum"], "payload": {"question_id": "cuet-phy-emwave-24", "subtopic": "electromagnetic spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "1 nm to 400 nm", "is_correct": false}, {"key": "B", "text": "400 nm to 700 nm", "is_correct": true}, {"key": "C", "text": "700 nm to 1 mm", "is_correct": false}, {"key": "D", "text": "1 mm to 1 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1–400 nm covers ultraviolet and X-ray ranges, which are invisible to the human eye.", "misconception": "Confusing UV range with visible light"}, {"option_key": "C", "hint": "700 nm to 1 mm is the infrared region, felt as heat but not seen by the eye.", "misconception": "Extending visible range into infrared"}, {"option_key": "D", "hint": "1 mm to 1 m is the microwave range, used in communication and cooking.", "misconception": "Confusing microwave with visible wavelengths"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If the electric field component of an EM wave is E₀ sin(kz − ωt)x̂, the magnetic field component is:", "explanation": "In an electromagnetic wave, E and B are perpendicular to each other and to the direction of propagation. If E is along x̂ and propagation is along ẑ, then B must be along ŷ. The amplitude relation is B₀ = E₀/c. Both fields have the same phase, so B = (E₀/c) sin(kz − ωt)ŷ.", "correct_answer": "A", "concept_tags": ["E-B-relation", "wave-propagation", "amplitude-ratio"], "payload": {"question_id": "cuet-phy-emwave-25", "subtopic": "relation between E and B", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "(E₀/c) sin(kz − ωt)ŷ", "is_correct": true}, {"key": "B", "text": "E₀c sin(kz − ωt)ŷ", "is_correct": false}, {"key": "C", "text": "(E₀/c) sin(kz − ωt)ẑ", "is_correct": false}, {"key": "D", "text": "(E₀/c) cos(kz − ωt)ŷ", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "B₀ = E₀/c, not E₀c. Since c ≈ 3×10⁸, E₀c would give an enormously large magnetic field.", "misconception": "Inverting the E-B amplitude relation"}, {"option_key": "C", "hint": "ẑ is the direction of propagation. B cannot oscillate along the direction of wave travel — EM waves are transverse.", "misconception": "Placing B along the propagation direction"}, {"option_key": "D", "hint": "E and B are in phase in an EM wave. If E has sin(kz − ωt), B also has sin(kz − ωt), not cos.", "misconception": "Thinking E and B have a 90° phase difference"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ozone layer in the Earth''s atmosphere absorbs mainly:", "explanation": "The ozone (O₃) layer in the stratosphere strongly absorbs ultraviolet (UV) radiation from the Sun, particularly UV-B (280–315 nm) and UV-C (100–280 nm). This absorption protects living organisms from harmful UV radiation that can cause skin cancer and DNA damage.", "correct_answer": "B", "concept_tags": ["ozone-layer", "uv-absorption", "atmosphere"], "payload": {"question_id": "cuet-phy-emwave-26", "subtopic": "applications and effects of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Infrared radiation", "is_correct": false}, {"key": "B", "text": "Ultraviolet radiation", "is_correct": true}, {"key": "C", "text": "Visible light", "is_correct": false}, {"key": "D", "text": "Radio waves", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Infrared is mainly absorbed by water vapour and CO₂ (greenhouse gases), not ozone.", "misconception": "Confusing ozone absorption with greenhouse effect"}, {"option_key": "C", "hint": "Visible light passes through the atmosphere largely unabsorbed — that''s why we can see the Sun.", "misconception": "Thinking ozone blocks visible light"}, {"option_key": "D", "hint": "Radio waves pass through the atmosphere and are not absorbed by ozone. The ionosphere reflects some radio waves.", "misconception": "Confusing ozone layer with ionosphere"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The displacement current through a parallel plate capacitor of capacitance C is related to the voltage V across it by:", "explanation": "Displacement current Id = ε₀(dΦE/dt). For a parallel plate capacitor, ΦE = Q/(ε₀) and Q = CV, so Id = dQ/dt = C(dV/dt). This equals the conduction current flowing in the external circuit, maintaining continuity of current through the capacitor gap.", "correct_answer": "C", "concept_tags": ["displacement-current", "capacitor", "maxwell"], "payload": {"question_id": "cuet-phy-emwave-27", "subtopic": "displacement current", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "Id = V/C", "is_correct": false}, {"key": "B", "text": "Id = CV", "is_correct": false}, {"key": "C", "text": "Id = C(dV/dt)", "is_correct": true}, {"key": "D", "text": "Id = V(dC/dt)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "V/C has units of V/F = Coulombs, not Amperes. Current must involve a time derivative.", "misconception": "Confusing charge with current"}, {"option_key": "B", "hint": "CV gives charge Q, not current. You need the rate of change of charge for current.", "misconception": "Forgetting that current is dQ/dt, not Q"}, {"option_key": "D", "hint": "Capacitance C is fixed for a given capacitor geometry; dC/dt = 0 under normal conditions.", "misconception": "Thinking capacitance varies with time"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following EM waves has the longest wavelength?", "explanation": "In the electromagnetic spectrum, radio waves have the longest wavelength (ranging from ~1 mm to thousands of kilometres). The order from longest to shortest wavelength is: radio > microwave > infrared > visible > UV > X-ray > gamma ray.", "correct_answer": "D", "concept_tags": ["spectrum-order", "wavelength-comparison", "radio-waves"], "payload": {"question_id": "cuet-phy-emwave-28", "subtopic": "electromagnetic spectrum ordering", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "X-rays", "is_correct": false}, {"key": "B", "text": "Infrared rays", "is_correct": false}, {"key": "C", "text": "Microwaves", "is_correct": false}, {"key": "D", "text": "Radio waves", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "X-rays have very short wavelengths (0.01–10 nm), among the shortest in the EM spectrum.", "misconception": "Confusing penetrating power with wavelength"}, {"option_key": "B", "hint": "Infrared has wavelengths from ~700 nm to 1 mm — longer than visible but shorter than microwaves and radio.", "misconception": "Thinking IR is the longest wavelength"}, {"option_key": "C", "hint": "Microwaves (1 mm to ~30 cm) are longer than IR but shorter than radio waves.", "misconception": "Confusing microwave and radio wave ranges"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An EM wave has a frequency of 5 × 10¹⁴ Hz. Its wavelength is:", "explanation": "Using c = fλ, we get λ = c/f = (3 × 10⁸)/(5 × 10¹⁴) = 6 × 10⁻⁷ m = 600 nm. This falls in the visible light range (orange-yellow region), confirming the answer is reasonable.", "correct_answer": "B", "concept_tags": ["wavelength-frequency", "c-equals-f-lambda", "numerical"], "payload": {"question_id": "cuet-phy-emwave-29", "subtopic": "wave equation c = fλ", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "6 × 10⁻⁵ m", "is_correct": false}, {"key": "B", "text": "6 × 10⁻⁷ m", "is_correct": true}, {"key": "C", "text": "6 × 10⁻⁹ m", "is_correct": false}, {"key": "D", "text": "6 × 10⁻³ m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6 × 10⁻⁵ m = 60 μm, which lies in the far infrared — too long for a frequency of 10¹⁴ Hz.", "misconception": "Error in power of ten calculation"}, {"option_key": "C", "hint": "6 × 10⁻⁹ m = 6 nm, which is in the X-ray range — way too short for visible frequency.", "misconception": "Subtracting exponents incorrectly: 8−14 ≠ −9"}, {"option_key": "D", "hint": "6 × 10⁻³ m = 6 mm lies in the microwave range. This would correspond to a much lower frequency (~50 GHz).", "misconception": "Major arithmetic error in exponents"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The intensity of an electromagnetic wave is proportional to:", "explanation": "The intensity (power per unit area) of an EM wave is I = ½ε₀cE₀², so it is proportional to the square of the amplitude of the electric field. Equivalently, I = B₀²c/(2μ₀). Intensity is proportional to E₀², not E₀ or E₀³.", "correct_answer": "B", "concept_tags": ["intensity", "electric-field-amplitude", "energy"], "payload": {"question_id": "cuet-phy-emwave-30", "subtopic": "intensity of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "E₀", "is_correct": false}, {"key": "B", "text": "E₀²", "is_correct": true}, {"key": "C", "text": "E₀³", "is_correct": false}, {"key": "D", "text": "1/E₀²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Intensity involves energy, which depends on the square of the field amplitude — just like kinetic energy depends on v².", "misconception": "Forgetting the squared dependence of energy on amplitude"}, {"option_key": "C", "hint": "No standard wave formula involves the cube of amplitude. Energy density is always proportional to amplitude².", "misconception": "Randomly guessing the power dependence"}, {"option_key": "D", "hint": "Intensity increases with stronger electric field. An inverse-square relation would mean weaker fields give more energy.", "misconception": "Inverting the relationship"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A plane electromagnetic wave of frequency 25 MHz travels in free space along the x-direction. At a particular point and time, E = 6.3 V/m ŷ. The magnetic field B at that point and time is:", "explanation": "B₀ = E₀/c = 6.3/(3 × 10⁸) = 2.1 × 10⁻⁸ T. Since E is along ŷ and wave propagates along x̂, B must be along ẑ (using E × B ∝ direction of propagation: ŷ × ẑ = x̂). So B = 2.1 × 10⁻⁸ T ẑ.", "correct_answer": "A", "concept_tags": ["E-B-numerical", "direction", "cross-product"], "payload": {"question_id": "cuet-phy-emwave-31", "subtopic": "E and B field calculation", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "2.1 × 10⁻⁸ T ẑ", "is_correct": true}, {"key": "B", "text": "2.1 × 10⁻⁸ T x̂", "is_correct": false}, {"key": "C", "text": "1.89 × 10⁹ T ẑ", "is_correct": false}, {"key": "D", "text": "2.1 × 10⁻⁸ T (−ẑ)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "x̂ is the direction of propagation. B cannot point along the wave''s travel direction — EM waves are transverse.", "misconception": "Placing B along propagation direction"}, {"option_key": "C", "hint": "This value uses B = Ec instead of B = E/c. The magnetic field amplitude is always much smaller than E in SI units.", "misconception": "Using B = Ec instead of B = E/c"}, {"option_key": "D", "hint": "For E along +ŷ and propagation along +x̂, E × B must give +x̂. ŷ × ẑ = x̂ (correct), but ŷ × (−ẑ) = −x̂ (wrong direction).", "misconception": "Getting the cross-product sign wrong"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An EM wave of wavelength λ is incident on a slit of width d. Diffraction effects are significant when:", "explanation": "Diffraction becomes significant when the wavelength is comparable to or larger than the obstacle/slit size, i.e., λ ≥ d (or d ≈ λ). When d >> λ, the wave passes through with negligible diffraction (ray optics limit). When d << λ, the wave bends around the slit almost completely.", "correct_answer": "C", "concept_tags": ["diffraction-condition", "wavelength-slit", "wave-nature"], "payload": {"question_id": "cuet-phy-emwave-32", "subtopic": "wave properties of EM radiation", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "d >> λ", "is_correct": false}, {"key": "B", "text": "d << λ", "is_correct": false}, {"key": "C", "text": "d ≈ λ", "is_correct": true}, {"key": "D", "text": "λ = 0", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "When d >> λ, the slit is much wider than the wavelength — light goes straight through with minimal bending (geometric optics).", "misconception": "Thinking large slit causes more diffraction"}, {"option_key": "B", "hint": "When d << λ, diffraction is extreme (wave bends around completely), but the question asks when effects become ''significant'' — the onset is at d ≈ λ.", "misconception": "Partially correct but not the threshold condition"}, {"option_key": "D", "hint": "λ = 0 would mean infinite frequency — no real wave has zero wavelength.", "misconception": "Not understanding the physical meaning"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The average energy density in an electromagnetic wave with electric field amplitude E₀ is:", "explanation": "The average energy density of an EM wave is u = ½ε₀E₀². This can also be written as u = B₀²/(2μ₀). The electric and magnetic field contributions are equal: uE = ¼ε₀E₀² and uB = ¼ε₀E₀², giving total u = ½ε₀E₀².", "correct_answer": "B", "concept_tags": ["energy-density", "electric-field", "average"], "payload": {"question_id": "cuet-phy-emwave-33", "subtopic": "energy in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "ε₀E₀²", "is_correct": false}, {"key": "B", "text": "½ε₀E₀²", "is_correct": true}, {"key": "C", "text": "¼ε₀E₀²", "is_correct": false}, {"key": "D", "text": "2ε₀E₀²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "ε₀E₀² is the peak energy density of the electric field alone. The average (over one cycle) introduces a factor of ½.", "misconception": "Forgetting to take the time average of sin²"}, {"option_key": "C", "hint": "¼ε₀E₀² is the average energy density of only the electric field part. You must add the equal magnetic field contribution.", "misconception": "Forgetting the magnetic field contribution"}, {"option_key": "D", "hint": "2ε₀E₀² is four times the correct answer. There''s no physical basis for this factor.", "misconception": "Doubling both peak and average incorrectly"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electromagnetic wave with the highest penetrating power is:", "explanation": "Gamma rays have the shortest wavelength and highest frequency among EM waves, giving them the highest energy per photon (E = hf). This high energy allows them to penetrate through most materials, including metals and body tissues. X-rays also penetrate well but less than gamma rays.", "correct_answer": "D", "concept_tags": ["penetrating-power", "gamma-rays", "energy-frequency"], "payload": {"question_id": "cuet-phy-emwave-34", "subtopic": "properties of EM spectrum regions", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Visible light", "is_correct": false}, {"key": "B", "text": "Infrared", "is_correct": false}, {"key": "C", "text": "X-rays", "is_correct": false}, {"key": "D", "text": "Gamma rays", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Visible light is blocked by opaque materials and has much lower photon energy than X-rays or gamma rays.", "misconception": "Thinking visible light penetrates well because we see through glass"}, {"option_key": "B", "hint": "Infrared is absorbed by most solids and has very low penetrating power compared to high-frequency radiation.", "misconception": "Confusing heat penetration with radiation penetration"}, {"option_key": "C", "hint": "X-rays have high penetrating power and are used in medical imaging, but gamma rays have even higher energy and penetrate more.", "misconception": "Thinking X-rays are the most penetrating — close but gamma rays exceed them"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Maxwell''s equations predict that the speed of electromagnetic waves in a medium of permittivity ε and permeability μ is:", "explanation": "From Maxwell''s equations, the wave speed in a medium is v = 1/√(με). In vacuum, this gives c = 1/√(μ₀ε₀) = 3 × 10⁸ m/s. In any medium, ε > ε₀ and μ > μ₀ (usually), so v < c — electromagnetic waves slow down in a medium.", "correct_answer": "A", "concept_tags": ["maxwell-speed", "permittivity", "permeability"], "payload": {"question_id": "cuet-phy-emwave-35", "subtopic": "Maxwell''s equations and wave speed", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "1/√(με)", "is_correct": true}, {"key": "B", "text": "√(με)", "is_correct": false}, {"key": "C", "text": "1/(με)", "is_correct": false}, {"key": "D", "text": "με", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "√(με) would give speed in units of √(H·F/m²). Dimensionally, speed should be m/s = 1/√(με).", "misconception": "Inverting the formula"}, {"option_key": "C", "hint": "1/(με) has wrong dimensions. Check: [1/(με)] = m²/(H·F) which is not m/s.", "misconception": "Forgetting the square root"}, {"option_key": "D", "hint": "με has dimensions of H·F/m² = s²/m². This is the reciprocal of speed squared, not speed.", "misconception": "Completely inverting the relationship"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The radiation pressure exerted by an electromagnetic wave of intensity I on a perfectly reflecting surface is:", "explanation": "When an EM wave of intensity I strikes a perfectly reflecting surface, the radiation pressure is p = 2I/c. For a perfectly absorbing surface, it would be I/c. The factor of 2 for reflection arises because the momentum change is doubled (like a ball bouncing off a wall vs. sticking to it).", "correct_answer": "C", "concept_tags": ["radiation-pressure", "reflection", "momentum"], "payload": {"question_id": "cuet-phy-emwave-36", "subtopic": "momentum and radiation pressure", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "I/c", "is_correct": false}, {"key": "B", "text": "I/c²", "is_correct": false}, {"key": "C", "text": "2I/c", "is_correct": true}, {"key": "D", "text": "Ic", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I/c is the radiation pressure for a perfectly absorbing (black) surface. Reflection doubles the momentum transfer.", "misconception": "Using the absorption formula for reflection"}, {"option_key": "B", "hint": "I/c² has units of kg/m³, not Pa (N/m²). Dimensionally incorrect for pressure.", "misconception": "Confusing with E = mc² related expressions"}, {"option_key": "D", "hint": "Ic would have units of W²·s/m³ which is not pressure. Also, pressure should decrease with increasing c.", "misconception": "Inverting the c dependence"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following is used in the treatment of cancer?", "explanation": "Gamma rays are used in radiation therapy (radiotherapy) for cancer treatment. Their high energy and penetrating power allow them to destroy cancer cells deep within the body. Cobalt-60 is a common gamma ray source used in cancer treatment. Infrared is used for physiotherapy, UV for sterilisation, and microwaves for communication.", "correct_answer": "A", "concept_tags": ["gamma-rays", "cancer-treatment", "medical-applications"], "payload": {"question_id": "cuet-phy-emwave-37", "subtopic": "medical applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Gamma rays", "is_correct": true}, {"key": "B", "text": "Infrared rays", "is_correct": false}, {"key": "C", "text": "Radio waves", "is_correct": false}, {"key": "D", "text": "Microwaves", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Infrared radiation is used for heating and physiotherapy, not for destroying cancer cells.", "misconception": "Confusing thermal therapy with radiation therapy"}, {"option_key": "C", "hint": "Radio waves have very low energy and cannot damage or destroy cells. They are used in communication.", "misconception": "Thinking all radiation can treat cancer"}, {"option_key": "D", "hint": "Microwaves are used in cooking and communication. While microwave ablation exists in surgery, standard cancer radiotherapy uses gamma rays.", "misconception": "Confusing microwave heating with radiation therapy"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The source of infrared radiation is:", "explanation": "All hot bodies emit infrared radiation. Infrared is thermal radiation — any object above absolute zero emits IR, but hot bodies like heaters, the Sun, and human bodies emit significant amounts. IR is detected as heat by our skin.", "correct_answer": "B", "concept_tags": ["infrared", "thermal-radiation", "hot-bodies"], "payload": {"question_id": "cuet-phy-emwave-38", "subtopic": "sources of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Nuclear reactions", "is_correct": false}, {"key": "B", "text": "Hot bodies", "is_correct": true}, {"key": "C", "text": "X-ray tubes", "is_correct": false}, {"key": "D", "text": "Electronic oscillators", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear reactions primarily produce gamma rays, not infrared. The energy scale is completely different.", "misconception": "Confusing nuclear radiation with thermal radiation"}, {"option_key": "C", "hint": "X-ray tubes produce X-rays by bombarding a metal target with high-speed electrons, not infrared.", "misconception": "Confusing X-ray production with IR emission"}, {"option_key": "D", "hint": "Electronic oscillators produce radio waves and microwaves, not infrared.", "misconception": "Confusing electronic oscillation frequencies with thermal emission"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The momentum carried by an electromagnetic wave of energy U is:", "explanation": "Electromagnetic waves carry momentum p = U/c, where U is the energy and c is the speed of light. This follows from the relativistic energy-momentum relation for massless particles (photons): E = pc. This momentum is responsible for radiation pressure.", "correct_answer": "A", "concept_tags": ["momentum", "energy-momentum", "photon"], "payload": {"question_id": "cuet-phy-emwave-39", "subtopic": "energy and momentum of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "U/c", "is_correct": true}, {"key": "B", "text": "Uc", "is_correct": false}, {"key": "C", "text": "U/c²", "is_correct": false}, {"key": "D", "text": "Uc²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Uc has units of J·m/s = kg·m³/s³. Momentum should have units of kg·m/s.", "misconception": "Inverting the c relationship"}, {"option_key": "C", "hint": "U/c² has units of kg, which is mass — not momentum. This comes from E = mc², a different relation.", "misconception": "Confusing p = U/c with m = E/c²"}, {"option_key": "D", "hint": "Uc² has units of J·m²/s² — dimensionally incorrect for momentum.", "misconception": "Random combination of E and c"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A laser beam of power 10 W is focused on an area of 10⁻⁴ m². The amplitude of the electric field of the EM wave is approximately:", "explanation": "Intensity I = Power/Area = 10/10⁻⁴ = 10⁵ W/m². Using I = ½ε₀cE₀², we get E₀² = 2I/(ε₀c) = 2 × 10⁵/(8.85 × 10⁻¹² × 3 × 10⁸) = 2 × 10⁵/2.655 × 10⁻³ ≈ 7.53 × 10⁷. So E₀ ≈ √(7.53 × 10⁷) ≈ 8.68 × 10³ ≈ 8.7 kV/m.", "correct_answer": "C", "concept_tags": ["intensity-calculation", "electric-field-amplitude", "laser"], "payload": {"question_id": "cuet-phy-emwave-40", "subtopic": "numerical problems on intensity", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "8.7 V/m", "is_correct": false}, {"key": "B", "text": "87 V/m", "is_correct": false}, {"key": "C", "text": "8.7 kV/m", "is_correct": true}, {"key": "D", "text": "87 kV/m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8.7 V/m is 1000× too small. Check: I for E₀ = 8.7 V/m gives I ≈ 0.1 W/m², not 10⁵ W/m².", "misconception": "Order of magnitude error in calculation"}, {"option_key": "B", "hint": "87 V/m gives I ≈ 10 W/m². Still 10⁴ times less than the required 10⁵ W/m².", "misconception": "Arithmetic error — off by factor of 100"}, {"option_key": "D", "hint": "87 kV/m gives I ≈ 10⁷ W/m², which is 100× more than the given intensity.", "misconception": "Overshooting by a factor of 10 in E₀"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electromagnetic waves are transverse in nature.\nReason (R): The electric and magnetic field vectors are perpendicular to each other and to the direction of propagation.", "explanation": "Both A and R are true, and R correctly explains A. EM waves are transverse because E and B oscillate perpendicular to the propagation direction. This is fundamentally different from longitudinal waves (like sound) where oscillation is along the propagation direction.", "correct_answer": "A", "concept_tags": ["transverse-nature", "E-B-perpendicular", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-emwave-41", "subtopic": "nature of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The perpendicularity of E, B, and the propagation direction is precisely what makes the wave transverse. R directly explains A.", "misconception": "Thinking the explanation is unrelated"}, {"option_key": "C", "hint": "R is factually correct — E ⊥ B ⊥ direction of propagation is a well-established property of EM waves.", "misconception": "Doubting the perpendicularity of E and B"}, {"option_key": "D", "hint": "A is true — EM waves are indeed transverse. This is confirmed by polarisation experiments.", "misconception": "Thinking EM waves are longitudinal"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The energy of an electromagnetic wave is shared equally between the electric and magnetic fields.\nReason (R): The electric energy density uE = ½ε₀E² equals the magnetic energy density uB = B²/(2μ₀) at every instant in an EM wave.", "explanation": "Both A and R are true, and R correctly explains A. In an EM wave, since B = E/c and c = 1/√(μ₀ε₀), we can show that ½ε₀E² = B²/(2μ₀) at every instant. The energy oscillates between zero and maximum, but at each instant the electric and magnetic contributions are exactly equal.", "correct_answer": "A", "concept_tags": ["energy-equipartition", "energy-density", "E-B-equality"], "payload": {"question_id": "cuet-phy-emwave-42", "subtopic": "energy distribution in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyse", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly proves A — if uE = uB at every instant, then the energy is equally shared. R is the explanation.", "misconception": "Not seeing the direct logical connection"}, {"option_key": "C", "hint": "R is true: substituting B = E/c into B²/(2μ₀) gives E²/(2c²μ₀) = ½ε₀E² since c² = 1/(μ₀ε₀).", "misconception": "Not verifying the mathematical equality"}, {"option_key": "D", "hint": "A is true — equal energy sharing is a fundamental property derived from Maxwell''s equations.", "misconception": "Thinking one field dominates the other"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Radio waves can diffract around buildings and hills.\nReason (R): Radio waves have wavelengths comparable to the size of buildings and hills.", "explanation": "Both A and R are true, and R correctly explains A. Radio waves have wavelengths from metres to kilometres, which are comparable to the size of buildings and hills. Diffraction is significant when the obstacle size is comparable to the wavelength, so radio waves bend around these structures. This is why AM radio signals can be received even behind mountains.", "correct_answer": "A", "concept_tags": ["radio-diffraction", "wavelength-obstacle", "diffraction"], "payload": {"question_id": "cuet-phy-emwave-43", "subtopic": "diffraction of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The comparable wavelength is precisely why diffraction occurs. R is the direct cause of A.", "misconception": "Not connecting diffraction condition to wavelength"}, {"option_key": "C", "hint": "R is correct: AM radio wavelengths are ~100–1000 m, comparable to building and hill sizes.", "misconception": "Underestimating radio wavelengths"}, {"option_key": "D", "hint": "A is true — radio reception behind obstacles is daily evidence of radio wave diffraction.", "misconception": "Thinking radio needs line-of-sight"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Displacement current does not produce a magnetic field.\nReason (R): Displacement current is not a flow of charges.", "explanation": "A is false but R is true. Displacement current IS NOT a flow of charges (R is true — it arises from changing electric field). However, displacement current DOES produce a magnetic field, exactly like conduction current (A is false). This was Maxwell''s key insight: a changing electric field between capacitor plates produces a magnetic field, maintaining the continuity of the Ampere''s circuital law.", "correct_answer": "D", "concept_tags": ["displacement-current", "maxwell-insight", "magnetic-field"], "payload": {"question_id": "cuet-phy-emwave-44", "subtopic": "displacement current and Maxwell''s correction", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyse", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A is false — displacement current does produce a magnetic field. That''s the whole point of Maxwell''s modification to Ampere''s law.", "misconception": "Thinking displacement current has no magnetic effect"}, {"option_key": "B", "hint": "A is false, so this option cannot be correct.", "misconception": "Same as above"}, {"option_key": "C", "hint": "R is true — displacement current is ε₀(dΦE/dt), not a flow of actual charges. It exists even in vacuum.", "misconception": "Confusing displacement current with conduction current"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following electromagnetic waves (Column-I) with their sources (Column-II):\n\nColumn-I: (P) Radio waves (Q) X-rays (R) Gamma rays (S) Infrared\nColumn-II: (1) Radioactive nuclei (2) Vibration of atoms/molecules (3) Accelerating electrons striking metal target (4) Oscillating electric circuits", "explanation": "P→4: Radio waves are produced by oscillating charges in LC circuits and antennas. Q→3: X-rays are produced when high-speed electrons decelerate upon hitting a metal target (Bremsstrahlung). R→1: Gamma rays originate from nuclear transitions in radioactive decay. S→2: Infrared radiation is emitted by vibrating atoms and molecules (thermal motion).", "correct_answer": "B", "concept_tags": ["sources", "matching", "spectrum-production"], "payload": {"question_id": "cuet-phy-emwave-45", "subtopic": "sources of different EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→1, Q→3, R→4, S→2", "is_correct": false}, {"key": "B", "text": "P→4, Q→3, R→1, S→2", "is_correct": true}, {"key": "C", "text": "P→4, Q→1, R→3, S→2", "is_correct": false}, {"key": "D", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P→1 means radio waves from radioactive nuclei — incorrect. Nuclear decay produces gamma rays, not radio waves.", "misconception": "Confusing nuclear radiation with radio transmission"}, {"option_key": "C", "hint": "Q→1 implies X-rays from radioactive nuclei. While some nuclei emit X-rays, the primary source is electron deceleration in X-ray tubes (3).", "misconception": "Confusing gamma emission with X-ray production"}, {"option_key": "D", "hint": "P→2 means radio waves from atomic vibrations — incorrect. Atomic vibrations produce infrared, not radio waves.", "misconception": "Confusing thermal radiation with radio waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following electromagnetic waves (Column-I) with their approximate frequency ranges (Column-II):\n\nColumn-I: (P) Microwaves (Q) Visible light (R) Ultraviolet (S) X-rays\nColumn-II: (1) 10¹⁵ to 10¹⁷ Hz (2) 4 × 10¹⁴ to 7.5 × 10¹⁴ Hz (3) 10⁹ to 10¹² Hz (4) 10¹⁷ to 10²⁰ Hz", "explanation": "P→3: Microwaves have frequencies from ~10⁹ to 10¹² Hz (GHz range). Q→2: Visible light spans ~4 × 10¹⁴ Hz (red) to ~7.5 × 10¹⁴ Hz (violet). R→1: UV radiation spans ~10¹⁵ to 10¹⁷ Hz. S→4: X-rays have frequencies from ~10¹⁷ to 10²⁰ Hz.", "correct_answer": "A", "concept_tags": ["frequency-ranges", "spectrum-ordering", "matching"], "payload": {"question_id": "cuet-phy-emwave-46", "subtopic": "frequency ranges of EM spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→3, Q→2, R→1, S→4", "is_correct": true}, {"key": "B", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "C", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→4, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Q→1 assigns 10¹⁵–10¹⁷ Hz to visible light, which is actually the UV range. Visible is only ~4–7.5 × 10¹⁴ Hz.", "misconception": "Overestimating visible light frequency"}, {"option_key": "C", "hint": "P→2 assigns ~10¹⁴ Hz to microwaves. Microwaves are much lower frequency (~10⁹–10¹² Hz).", "misconception": "Confusing microwave and visible frequencies"}, {"option_key": "D", "hint": "R→4 assigns 10¹⁷–10²⁰ Hz to UV, but that''s the X-ray range. UV is lower frequency than X-rays.", "misconception": "Swapping UV and X-ray frequency ranges"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following EM wave applications (Column-I) with the type of EM wave used (Column-II):\n\nColumn-I: (P) Night vision cameras (Q) Satellite communication (R) Sterilisation of surgical instruments (S) Medical imaging of bones\nColumn-II: (1) X-rays (2) Ultraviolet (3) Microwaves (4) Infrared", "explanation": "P→4: Night vision uses infrared cameras to detect heat emitted by bodies. Q→3: Satellite communication uses microwaves which can penetrate the ionosphere. R→2: UV radiation kills bacteria and is used for sterilisation. S→1: X-rays penetrate soft tissue but are absorbed by bones, creating contrast images.", "correct_answer": "C", "concept_tags": ["applications", "matching", "practical-uses"], "payload": {"question_id": "cuet-phy-emwave-47", "subtopic": "applications of EM spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→4, Q→3, R→1, S→2", "is_correct": false}, {"key": "B", "text": "P→3, Q→4, R→2, S→1", "is_correct": false}, {"key": "C", "text": "P→4, Q→3, R→2, S→1", "is_correct": true}, {"key": "D", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R→1 means sterilisation with X-rays — UV is the standard sterilisation method, not X-rays.", "misconception": "Confusing X-ray imaging with UV sterilisation"}, {"option_key": "B", "hint": "P→3 means night vision with microwaves — night vision cameras detect infrared (heat), not microwaves.", "misconception": "Confusing thermal IR with microwave detection"}, {"option_key": "D", "hint": "Q→2 means satellite communication with UV — UV is absorbed by the atmosphere. Microwaves pass through.", "misconception": "Thinking UV can be used for long-range communication"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electromagnetic waves require a material medium for their propagation.", "explanation": "This statement is FALSE. Electromagnetic waves are self-sustaining oscillations of electric and magnetic fields and do NOT require a material medium. They can propagate through vacuum at the speed of light. This is fundamentally different from mechanical waves like sound, which need a medium.", "correct_answer": "B", "concept_tags": ["vacuum-propagation", "no-medium", "em-vs-mechanical"], "payload": {"question_id": "cuet-phy-emwave-48", "subtopic": "properties of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Sunlight reaches us through the vacuum of space — clear proof that EM waves don''t need a medium.", "misconception": "Confusing EM waves with sound waves which do need a medium"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "X-rays have a higher frequency than ultraviolet rays.", "explanation": "This statement is TRUE. In the EM spectrum, frequency increases as: radio < microwave < IR < visible < UV < X-rays < gamma rays. X-rays (10¹⁷–10²⁰ Hz) have higher frequency than UV (10¹⁵–10¹⁷ Hz).", "correct_answer": "A", "concept_tags": ["frequency-ordering", "x-rays-vs-uv", "spectrum"], "payload": {"question_id": "cuet-phy-emwave-49", "subtopic": "EM spectrum ordering", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "X-rays are more energetic than UV — since E = hf, higher energy means higher frequency.", "misconception": "Reversing the order of X-rays and UV in the spectrum"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "In an electromagnetic wave, the electric and magnetic fields are in phase with each other.", "explanation": "This statement is TRUE. In an EM wave, E and B reach their maximum, minimum, and zero values simultaneously — they oscillate in phase. If E = E₀ sin(kx − ωt), then B = B₀ sin(kx − ωt) with the same phase. They differ in direction (perpendicular) and magnitude (B₀ = E₀/c), but not in phase.", "correct_answer": "A", "concept_tags": ["phase-relation", "E-B-in-phase", "wave-properties"], "payload": {"question_id": "cuet-phy-emwave-50", "subtopic": "phase relationship in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Unlike standing waves or LC oscillations where E and B are 90° out of phase, in a travelling EM wave they are always in phase.", "misconception": "Confusing travelling wave with standing wave or LC circuit phase relations"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "The displacement current between the plates of a charging capacitor is equal to the conduction current in the external circuit.", "explanation": "This statement is TRUE. Maxwell showed that the displacement current Id = ε₀(dΦE/dt) between the capacitor plates equals the conduction current Ic in the connecting wires. This ensures continuity of current through the circuit, including the gap between the capacitor plates where no charges actually flow.", "correct_answer": "A", "concept_tags": ["displacement-current", "conduction-current", "continuity"], "payload": {"question_id": "cuet-phy-emwave-51", "subtopic": "displacement current", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If Id ≠ Ic, Kirchhoff''s current law would be violated at the capacitor terminals. Maxwell''s correction precisely ensures Id = Ic.", "misconception": "Thinking current is discontinuous at capacitor plates"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The part of the electromagnetic spectrum used in television remote controls is ______.", "explanation": "Television remote controls use infrared (IR) radiation. They emit IR light pulses in coded patterns that are received by an IR sensor on the TV. IR is used because it is invisible, safe, low-power, and works well over short distances within a room.", "correct_answer": "C", "concept_tags": ["infrared", "remote-control", "applications"], "payload": {"question_id": "cuet-phy-emwave-52", "subtopic": "everyday applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Radio waves", "is_correct": false}, {"key": "B", "text": "Microwaves", "is_correct": false}, {"key": "C", "text": "Infrared", "is_correct": true}, {"key": "D", "text": "Ultraviolet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Radio waves are used for broadcast communication (FM/AM radio, WiFi), not for TV remote controls.", "misconception": "Confusing radio broadcast with remote control"}, {"option_key": "B", "hint": "Microwaves are used in ovens and long-distance communication, not in handheld remote controls.", "misconception": "Confusing different wireless technologies"}, {"option_key": "D", "hint": "UV radiation can be harmful to eyes and skin. It would be unsafe and impractical for a consumer remote control.", "misconception": "Thinking any invisible radiation works for remotes"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "Maxwell added ______ current to Ampere''s circuital law to make it consistent for both steady and time-varying fields.", "explanation": "Maxwell added the displacement current (Id = ε₀ dΦE/dt) to Ampere''s circuital law. The original law worked for steady currents but failed for time-varying fields (e.g., between capacitor plates during charging). The modified law is: ∮B·dl = μ₀(Ic + Id), where Ic is conduction current and Id is displacement current.", "correct_answer": "B", "concept_tags": ["displacement-current", "ampere-law", "maxwell-correction"], "payload": {"question_id": "cuet-phy-emwave-53", "subtopic": "Maxwell''s modification of Ampere''s law", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Conduction", "is_correct": false}, {"key": "B", "text": "Displacement", "is_correct": true}, {"key": "C", "text": "Convection", "is_correct": false}, {"key": "D", "text": "Eddy", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Conduction current was already in the original Ampere''s law. Maxwell added something new, not what was already there.", "misconception": "Confusing existing term with the new addition"}, {"option_key": "C", "hint": "Convection current refers to charge transport in fluids. It is not related to Maxwell''s theoretical correction.", "misconception": "Random guess among current types"}, {"option_key": "D", "hint": "Eddy currents are induced circular currents in conductors, related to Faraday''s law — not Maxwell''s correction to Ampere''s law.", "misconception": "Confusing Faraday''s law effects with Maxwell''s addition"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The speed of light in vacuum, c = 1/√(μ₀ε₀), has a value of approximately ______ m/s.", "explanation": "Using μ₀ = 4π × 10⁻⁷ H/m and ε₀ = 8.854 × 10⁻¹² F/m, c = 1/√(μ₀ε₀) = 1/√(4π × 10⁻⁷ × 8.854 × 10⁻¹²) ≈ 3 × 10⁸ m/s. This value was calculated by Maxwell and matched the experimentally known speed of light, leading him to conclude that light is an electromagnetic wave.", "correct_answer": "A", "concept_tags": ["speed-of-light", "mu-epsilon", "maxwell-prediction"], "payload": {"question_id": "cuet-phy-emwave-54", "subtopic": "derivation of speed of light", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "3 × 10⁸", "is_correct": true}, {"key": "B", "text": "3 × 10⁶", "is_correct": false}, {"key": "C", "text": "3 × 10¹⁰", "is_correct": false}, {"key": "D", "text": "3 × 10⁵", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "3 × 10⁶ m/s is about 1% of the speed of light. Light travels ~300,000 km/s, not 3,000 km/s.", "misconception": "Off by a factor of 100"}, {"option_key": "C", "hint": "3 × 10¹⁰ m/s exceeds the speed of light by 100×. Nothing can travel this fast according to relativity.", "misconception": "Confusing with c in cm/s (3 × 10¹⁰ cm/s)"}, {"option_key": "D", "hint": "3 × 10⁵ m/s is approximately the speed of sound in some metals, not the speed of light.", "misconception": "Off by three orders of magnitude"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student is studying the electromagnetic spectrum and notes the following observations:\n(i) A TV remote works by emitting invisible radiation detected by a sensor on the TV.\n(ii) Mobile phones use radiation that can pass through walls but has less energy than light.\n(iii) Hospital X-ray machines can see through skin but not through bones.\n\nWhich of the following correctly identifies all three types of radiation?", "explanation": "(i) TV remotes use infrared radiation — invisible, low energy, short range. (ii) Mobile phones use microwaves — they can penetrate walls, have lower frequency (hence lower energy) than visible light. (iii) X-rays penetrate soft tissue but are absorbed by dense bone, creating contrast images. The correct identification is IR, Microwaves, X-rays.", "correct_answer": "B", "concept_tags": ["spectrum-identification", "real-world", "scenario"], "payload": {"question_id": "cuet-phy-emwave-55", "subtopic": "identifying EM waves from properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "(i) UV, (ii) Radio waves, (iii) X-rays", "is_correct": false}, {"key": "B", "text": "(i) Infrared, (ii) Microwaves, (iii) X-rays", "is_correct": true}, {"key": "C", "text": "(i) Infrared, (ii) Radio waves, (iii) Gamma rays", "is_correct": false}, {"key": "D", "text": "(i) Radio waves, (ii) Microwaves, (iii) X-rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "UV is not used in TV remotes — it would be harmful to emit UV radiation directly at people. Remotes use safe infrared.", "misconception": "Confusing invisible UV with invisible IR"}, {"option_key": "C", "hint": "Mobile phones use microwaves (GHz range), not radio waves (MHz range). Also, hospital imaging uses X-rays, not gamma rays.", "misconception": "Confusing microwave with radio, and X-ray with gamma"}, {"option_key": "D", "hint": "TV remotes emit infrared, not radio waves. Radio waves have much longer wavelengths and are used for broadcasting.", "misconception": "Thinking any wireless device uses radio waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A parallel plate capacitor with plate area A = 2 × 10⁻² m² is being charged by a current of 0.5 A. The electric field between the plates changes uniformly.\n\nThe displacement current between the plates is:", "explanation": "The displacement current Id between capacitor plates equals the conduction current Ic in the external circuit (Maxwell''s continuity principle). Since Ic = 0.5 A, Id = 0.5 A. This can be verified: Id = ε₀(dΦE/dt) = ε₀A(dE/dt). Since the charging current provides dQ/dt = 0.5 A, and Q = ε₀AE, we get ε₀A(dE/dt) = dQ/dt = 0.5 A.", "correct_answer": "B", "concept_tags": ["displacement-current-calculation", "capacitor-charging", "maxwell"], "payload": {"question_id": "cuet-phy-emwave-56", "subtopic": "displacement current numerical", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "0.25 A", "is_correct": false}, {"key": "B", "text": "0.5 A", "is_correct": true}, {"key": "C", "text": "1.0 A", "is_correct": false}, {"key": "D", "text": "Depends on the plate area", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Id = Ic always (for a charging capacitor). The displacement current is NOT half the conduction current.", "misconception": "Thinking displacement current is half of conduction current"}, {"option_key": "C", "hint": "Id = Ic = 0.5 A, not 2 × Ic. There is no doubling factor in the Id-Ic relationship.", "misconception": "Doubling the current incorrectly"}, {"option_key": "D", "hint": "While ε₀A(dE/dt) depends on area, the result always equals Ic regardless of plate dimensions. The area cancels out.", "misconception": "Thinking displacement current depends on plate geometry independently of conduction current"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "An astronaut on the International Space Station communicates with ground control using radio signals. The ISS orbits at a height of approximately 400 km above Earth''s surface.\n\nThe time delay for the radio signal to travel from ISS to Earth is approximately:", "explanation": "Radio signals travel at the speed of light, c = 3 × 10⁸ m/s. Distance = 400 km = 4 × 10⁵ m. Time = distance/speed = 4 × 10⁵/(3 × 10⁸) = 1.33 × 10⁻³ s ≈ 1.3 ms. This is barely perceptible in conversation.", "correct_answer": "B", "concept_tags": ["speed-distance-time", "space-communication", "practical"], "payload": {"question_id": "cuet-phy-emwave-57", "subtopic": "EM wave speed applications", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "0.13 ms", "is_correct": false}, {"key": "B", "text": "1.3 ms", "is_correct": true}, {"key": "C", "text": "13 ms", "is_correct": false}, {"key": "D", "text": "1.3 s", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.13 ms corresponds to only 40 km distance, not 400 km. Check the exponent calculation.", "misconception": "Error in power of ten"}, {"option_key": "C", "hint": "13 ms corresponds to ~4000 km, which is 10× the actual ISS height.", "misconception": "Using 4 × 10⁶ m instead of 4 × 10⁵ m"}, {"option_key": "D", "hint": "1.3 s would mean a distance of ~400,000 km — roughly the Earth-Moon distance, not ISS height.", "misconception": "Major order of magnitude error"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A plane EM wave has an electric field amplitude of 480 V/m. The magnetic field amplitude and the average intensity of the wave are respectively:", "explanation": "B₀ = E₀/c = 480/(3 × 10⁸) = 1.6 × 10⁻⁶ T. Average intensity I = ½ε₀cE₀² = ½ × 8.85 × 10⁻¹² × 3 × 10⁸ × (480)² = ½ × 8.85 × 10⁻¹² × 3 × 10⁸ × 2.304 × 10⁵ = ½ × 611.5 ≈ 306 W/m².", "correct_answer": "A", "concept_tags": ["numerical", "B-amplitude", "intensity-calculation"], "payload": {"question_id": "cuet-phy-emwave-58", "subtopic": "E, B amplitude and intensity", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6 × 10⁻⁶ T, 306 W/m²", "is_correct": true}, {"key": "B", "text": "1.6 × 10⁻⁶ T, 612 W/m²", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻⁸ T, 306 W/m²", "is_correct": false}, {"key": "D", "text": "1.6 × 10⁻⁶ T, 153 W/m²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "612 W/m² is the peak intensity (ε₀cE₀²), not the average. For average, you need the ½ factor from time-averaging sin².", "misconception": "Forgetting the ½ factor in average intensity"}, {"option_key": "C", "hint": "1.6 × 10⁻⁸ T is 100× too small. B₀ = E₀/c = 480/(3×10⁸) = 1.6 × 10⁻⁶ T.", "misconception": "Arithmetic error in exponents: 10⁰/10⁸ ≠ 10⁻⁸ for this calculation"}, {"option_key": "D", "hint": "153 W/m² is ¼ε₀cE₀², which counts only the electric field contribution. Total intensity includes both E and B.", "misconception": "Forgetting to add the magnetic field energy contribution"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which property of electromagnetic waves proves that they are transverse?", "explanation": "Polarisation is exclusively a property of transverse waves. Only waves whose oscillations are perpendicular to the propagation direction can be polarised (restricted to a single plane). Longitudinal waves like sound cannot be polarised. The fact that light can be polarised (using Polaroid filters, for example) proves it is transverse.", "correct_answer": "C", "concept_tags": ["polarisation", "transverse-proof", "wave-nature"], "payload": {"question_id": "cuet-phy-emwave-59", "subtopic": "evidence for transverse nature", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Reflection", "is_correct": false}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Polarisation", "is_correct": true}, {"key": "D", "text": "Interference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Both transverse and longitudinal waves can be reflected. Reflection doesn''t distinguish wave type.", "misconception": "Thinking reflection is unique to transverse waves"}, {"option_key": "B", "hint": "Diffraction occurs for all types of waves — it proves wave nature but not transverse nature.", "misconception": "Confusing wave nature with transverse nature"}, {"option_key": "D", "hint": "Interference occurs for both longitudinal and transverse waves (e.g., sound interference). It proves wave nature, not transverse nature.", "misconception": "Confusing general wave properties with transverse-specific properties"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field of a sinusoidal EM wave in vacuum obeys the equation E = 100 sin(5 × 10⁶ t − kx) V/m. The wavelength of the wave is:", "explanation": "From the equation, ω = 5 × 10⁶ rad/s. Frequency f = ω/(2π) = 5 × 10⁶/(2π) Hz. Using c = fλ, we get λ = c/f = 2πc/ω = 2π × 3 × 10⁸/(5 × 10⁶) = 6π × 10⁸/5 × 10⁶ = 6π × 10² ≈ 120π m ≈ 377 m. Alternatively, k = ω/c = 5 × 10⁶/(3 × 10⁸) = 1.67 × 10⁻² rad/m, and λ = 2π/k = 2π/(1.67 × 10⁻²) ≈ 376.8 m.", "correct_answer": "D", "concept_tags": ["wave-equation", "wavelength-from-omega", "numerical"], "payload": {"question_id": "cuet-phy-emwave-60", "subtopic": "EM wave equation analysis", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "60 m", "is_correct": false}, {"key": "B", "text": "60π m", "is_correct": false}, {"key": "C", "text": "12π m", "is_correct": false}, {"key": "D", "text": "120π m", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "60 m forgets the 2π factor. λ = 2πc/ω, not c/ω.", "misconception": "Using λ = c/ω instead of λ = 2πc/ω"}, {"option_key": "B", "hint": "60π m uses λ = πc/ω. The correct formula is λ = 2πc/ω = 2π × 3 × 10⁸/(5 × 10⁶).", "misconception": "Using π instead of 2π"}, {"option_key": "C", "hint": "12π m comes from an error in the power of ten: 10⁸/10⁶ = 10² = 100, not 10.", "misconception": "Arithmetic error in exponent subtraction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A long straight wire carries a current of 10 A. The magnetic field at a perpendicular distance of 0.1 m from the wire is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a long straight conductor, B = μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = (4π × 10⁻⁶)/(0.2π) = 2 × 10⁻⁵ T = 20 μT.", "correct_answer": "C", "concept_tags": ["straight-conductor", "magnetic-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-01", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "2 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "2 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "2 × 10⁻⁷ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Recheck the calculation: μ₀I/(2πd) = (4π × 10⁻⁷ × 10)/(2π × 0.1) = 2 × 10⁻⁵ T.", "misconception": "Arithmetic error with powers of 10"}, {"option_key": "B", "hint": "This is 100 times too large. The denominator 2πd = 2π × 0.1 ≈ 0.628, and dividing 4π × 10⁻⁶ by this gives 2 × 10⁻⁵, not 2 × 10⁻⁴.", "misconception": "Error in handling decimal distance"}, {"option_key": "D", "hint": "This equals μ₀/2π, which would correspond to I = 1 A at d = 1 m. With I = 10 A and d = 0.1 m, the field is much larger.", "misconception": "Using default values instead of given values"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law states that the line integral of magnetic field B around a closed loop equals:", "explanation": "Ampere''s circuital law states ∮B·dl = μ₀I_enclosed, where I_enclosed is the total current threading through the closed Amperian loop. This law is analogous to Gauss''s law in electrostatics and is most useful when the magnetic field has high symmetry.", "correct_answer": "D", "concept_tags": ["ampere-law", "line-integral", "enclosed-current"], "payload": {"question_id": "cuet-phy-mag-biot-02", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀ times the total current in the circuit", "is_correct": false}, {"key": "B", "text": "The total magnetic flux through the loop", "is_correct": false}, {"key": "C", "text": "μ₀ε₀ times the rate of change of electric flux", "is_correct": false}, {"key": "D", "text": "μ₀ times the net current enclosed by the loop", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Ampere''s law considers only the current enclosed by (threading through) the Amperian loop, not the total current in the entire circuit.", "misconception": "Confusing enclosed current with total circuit current"}, {"option_key": "B", "hint": "The line integral ∮B·dl gives μ₀I_enclosed, not magnetic flux. Magnetic flux is the surface integral ∫B·dA.", "misconception": "Confusing line integral of B with surface integral of B"}, {"option_key": "C", "hint": "This is Maxwell''s displacement current term, which is an addition to Ampere''s law. The basic Ampere''s circuital law relates ∮B·dl to μ₀I_enclosed.", "misconception": "Confusing Ampere''s law with Maxwell''s modification"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the Biot-Savart law, dB = (μ₀/4π)(Idl × r̂)/r², the direction of the magnetic field dB at a point is determined by:", "explanation": "In the Biot-Savart law, the magnetic field dB is given by the cross product Idl × r̂. The direction of this cross product is perpendicular to the plane containing the current element dl and the position vector r̂. This direction is found using the right-hand rule: curl the fingers from dl toward r̂, and the thumb points in the direction of dB.", "correct_answer": "A", "concept_tags": ["biot-savart-law", "cross-product", "right-hand-rule"], "payload": {"question_id": "cuet-phy-mag-biot-03", "subtopic": "Biot-Savart law vector form", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "The cross product dl × r̂, perpendicular to the plane of dl and r̂", "is_correct": true}, {"key": "B", "text": "The dot product dl · r̂, along the current element", "is_correct": false}, {"key": "C", "text": "Along the position vector r̂ joining the element to the point", "is_correct": false}, {"key": "D", "text": "Along the current element dl itself", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The dot product gives a scalar, not a vector direction. Biot-Savart law involves a cross product.", "misconception": "Confusing dot product with cross product in the Biot-Savart law"}, {"option_key": "C", "hint": "The magnetic field is perpendicular to r̂, not along it. This would describe an electric field direction.", "misconception": "Confusing magnetic field direction with electric field direction"}, {"option_key": "D", "hint": "dB is perpendicular to dl, not along it. A field along dl would violate the cross-product nature of the law.", "misconception": "Thinking the magnetic field is along the current direction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field at a perpendicular distance d from an infinitely long straight wire carrying current I is given by B = μ₀I/(2πd). If the current is doubled and the distance is halved, the new magnetic field becomes:", "explanation": "The magnetic field due to an infinite straight wire is B = μ₀I/(2πd). When current is doubled (I → 2I) and distance is halved (d → d/2), the new field B'' = μ₀(2I)/(2π × d/2) = μ₀(2I) × 2/(2πd) = 4 × μ₀I/(2πd) = 4B. The field becomes four times the original value.", "correct_answer": "B", "concept_tags": ["infinite-wire", "magnetic-field-proportionality", "inverse-distance"], "payload": {"question_id": "cuet-phy-mag-biot-04", "subtopic": "Infinite straight wire", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2B", "is_correct": false}, {"key": "B", "text": "4B", "is_correct": true}, {"key": "C", "text": "B", "is_correct": false}, {"key": "D", "text": "8B", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This only accounts for the doubling of current but ignores the effect of halving the distance.", "misconception": "Forgetting that B is inversely proportional to distance"}, {"option_key": "C", "hint": "Both current and distance changed, so the field cannot remain the same.", "misconception": "Thinking the effects of current and distance cancel out"}, {"option_key": "D", "hint": "B is proportional to I/d, not I/d². Halving d gives a factor of 2, not 4.", "misconception": "Confusing inverse-distance with inverse-square dependence"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "According to Biot-Savart law, the magnetic field dB due to a small current element Idl at a point P is proportional to:", "explanation": "The Biot-Savart law states dB = (μ₀/4π)(Idl × r̂)/r². The magnitude of dB is proportional to sinθ (from the cross product) and inversely proportional to r². Here θ is the angle between the current element dl and the position vector r pointing from the element to the point P.", "correct_answer": "A", "concept_tags": ["biot-savart-law", "magnetic-field", "current-element"], "payload": {"question_id": "cuet-phy-mag-biot-05", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "sinθ/r², where θ is the angle between dl and r", "is_correct": true}, {"key": "B", "text": "cosθ/r², where θ is the angle between dl and r", "is_correct": false}, {"key": "C", "text": "sinθ/r, where θ is the angle between dl and r", "is_correct": false}, {"key": "D", "text": "cosθ/r, where θ is the angle between dl and r", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Biot-Savart law involves a cross product (Idl × r̂), which gives sinθ, not cosθ. The cosθ dependence appears in electrostatics (e.g., electric flux), not here.", "misconception": "Confusing cross product with dot product"}, {"option_key": "C", "hint": "The field falls off as 1/r², not 1/r. The inverse-square dependence is analogous to Coulomb''s law.", "misconception": "Incorrect distance dependence"}, {"option_key": "D", "hint": "This has both the wrong angular dependence (cosθ instead of sinθ) and the wrong distance dependence (1/r instead of 1/r²).", "misconception": "Multiple errors in Biot-Savart law recall"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field at the centre of a circular loop of radius R carrying current I is:", "explanation": "Using the Biot-Savart law and integrating over the entire circular loop, every element dl is perpendicular to the position vector r (θ = 90°) and at a distance R from the centre. The integration gives B = μ₀I/(2R). This is a standard result frequently used in NEET problems.", "correct_answer": "B", "concept_tags": ["circular-loop", "magnetic-field-centre", "biot-savart-law"], "payload": {"question_id": "cuet-phy-mag-biot-06", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀I/(4πR)", "is_correct": false}, {"key": "B", "text": "μ₀I/(2R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀IR²/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(4πR) would result from integrating only a quarter of the loop. The full circular loop gives μ₀I/(2R).", "misconception": "Incomplete integration of the loop"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the magnetic field due to a long straight conductor at perpendicular distance R, not at the centre of a circular loop.", "misconception": "Confusing straight wire formula with circular loop formula"}, {"option_key": "D", "hint": "This expression has incorrect dimensions. μ₀IR²/2 has units of T·m³, not Tesla. The correct formula is μ₀I/(2R).", "misconception": "Dimensional error in the formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A straight conductor of length L carries a current I. The magnetic field at a point on the perpendicular bisector at a distance d from the conductor is B = (μ₀I/4πd)(2sinα), where α is the half-angle subtended by the conductor. As L → ∞, this expression reduces to:", "explanation": "For a finite straight conductor, B = (μ₀I/4πd)(sinα₁ + sinα₂). On the perpendicular bisector, α₁ = α₂ = α, so B = (μ₀I/4πd)(2sinα). As L → ∞, α → 90°, so sinα → 1. Therefore B = (μ₀I/4πd)(2) = μ₀I/(2πd), which is the well-known result for an infinite straight wire.", "correct_answer": "C", "concept_tags": ["finite-conductor", "infinite-wire-limit", "perpendicular-bisector"], "payload": {"question_id": "cuet-phy-mag-biot-07", "subtopic": "Magnetic field due to straight conductor", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "μ₀I/(4πd)", "is_correct": false}, {"key": "B", "text": "μ₀I/(πd)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πd)", "is_correct": true}, {"key": "D", "text": "μ₀I/(4πd²)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is missing the factor of 2 that comes from both halves of the infinite wire contributing equally.", "misconception": "Forgetting the limiting value of 2sinα as L → ∞"}, {"option_key": "B", "hint": "This is twice the correct answer. Check the algebra when substituting sinα = 1.", "misconception": "Arithmetic error in simplification"}, {"option_key": "D", "hint": "The field of a straight wire depends on 1/d, not 1/d². The inverse-square dependence is for point sources.", "misconception": "Confusing with Coulomb''s law distance dependence"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two parallel infinite wires separated by distance a carry currents I₁ and I₂ in the same direction. The magnetic field at a point midway between them is:", "explanation": "At the midpoint, the distance from each wire is a/2. Wire 1 produces B₁ = μ₀I₁/(2π × a/2) = μ₀I₁/(πa) directed (say) into the page. Wire 2 produces B₂ = μ₀I₂/(2π × a/2) = μ₀I₂/(πa) directed out of the page (by right-hand rule, since currents are in the same direction, the fields at the midpoint are in opposite directions). The net field is B = μ₀(I₁ − I₂)/(πa). When I₁ = I₂, the net field is zero.", "correct_answer": "D", "concept_tags": ["superposition", "parallel-wires", "right-hand-rule"], "payload": {"question_id": "cuet-phy-mag-biot-08", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀(I₁ + I₂)/(πa), always additive", "is_correct": false}, {"key": "B", "text": "Zero, regardless of the values of I₁ and I₂", "is_correct": false}, {"key": "C", "text": "μ₀I₁I₂/(πa²), proportional to the product of currents", "is_correct": false}, {"key": "D", "text": "μ₀(I₁ − I₂)/(πa), and zero when I₁ = I₂", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "For same-direction currents, the fields at the midpoint oppose each other, not add.", "misconception": "Ignoring direction of magnetic field when applying superposition"}, {"option_key": "B", "hint": "The field is zero only when I₁ = I₂. For unequal currents, there is a net field.", "misconception": "Assuming cancellation without checking current magnitudes"}, {"option_key": "C", "hint": "Magnetic field uses superposition (addition/subtraction of B), not multiplication of currents.", "misconception": "Confusing force between wires with field superposition"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a circular coil of radius R carrying current I is B₀. The magnetic field on the axis of the same coil at a distance R from the centre is:", "explanation": "The field at the centre is B₀ = μ₀I/(2R). The field on the axis at distance x from the centre is B = (μ₀IR²)/(2(R² + x²)^(3/2)). At x = R: B = (μ₀IR²)/(2(R² + R²)^(3/2)) = (μ₀IR²)/(2(2R²)^(3/2)) = (μ₀IR²)/(2 × 2√2 × R³) = μ₀I/(4√2 R) = B₀/(2√2). This can also be written as B₀√2/4.", "correct_answer": "C", "concept_tags": ["circular-loop-axis", "axial-field", "distance-dependence"], "payload": {"question_id": "cuet-phy-mag-biot-09", "subtopic": "Magnetic field due to circular loop on axis", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "B₀/2", "is_correct": false}, {"key": "B", "text": "B₀/4", "is_correct": false}, {"key": "C", "text": "B₀/(2√2)", "is_correct": true}, {"key": "D", "text": "B₀/√2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This ignores the (R² + x²)^(3/2) factor in the denominator. The decay is not simply 1/2 at x = R.", "misconception": "Assuming linear decay of field along axis"}, {"option_key": "B", "hint": "Check the power of (2R²)^(3/2). It equals 2√2 R³, not 4R³.", "misconception": "Error in evaluating (2)^(3/2)"}, {"option_key": "D", "hint": "This would require (R² + x²)^(3/2) = √2 R³, which is not correct for x = R.", "misconception": "Algebraic error in the axial field formula"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 0.5 m has 1000 turns and carries a current of 2 A. The magnetic field inside the solenoid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a solenoid, B = μ₀nI where n = N/L = 1000/0.5 = 2000 turns/m. B = 4π × 10⁻⁷ × 2000 × 2 = 4π × 10⁻⁷ × 4000 = 16π × 10⁻⁴ = 16 × 3.14 × 10⁻⁴ ≈ 5.03 × 10⁻³ T ≈ 5.03 mT.", "correct_answer": "C", "concept_tags": ["solenoid", "ampere-law", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-10", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2.51 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻³ T", "is_correct": false}, {"key": "C", "text": "5.03 × 10⁻³ T", "is_correct": true}, {"key": "D", "text": "5.03 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is exactly half the correct answer, suggesting you used N = 1000 instead of n = N/L = 2000 turns/m, or missed the current value.", "misconception": "Using total turns instead of turns per unit length"}, {"option_key": "B", "hint": "This would correspond to n = 1000 and I = 1, indicating errors in both n and I. Use n = N/L = 2000 turns/m and I = 2 A.", "misconception": "Multiple calculation errors"}, {"option_key": "D", "hint": "This is off by a factor of 10. Check the power of 10 in your calculation: μ₀nI = 4π × 10⁻⁷ × 2000 × 2 = 16π × 10⁻⁴ ≈ 5.03 × 10⁻³.", "misconception": "Power of 10 arithmetic error"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a quarter-circle arc of radius R carrying current I is:", "explanation": "A quarter-circle arc subtends an angle π/2 at the centre. Using the formula B = μ₀Iφ/(4πR) for an arc of angle φ: B = μ₀I(π/2)/(4πR) = μ₀I/(8R). The straight portions (if connected along radii) contribute zero field at the centre because the current element is parallel to the position vector (sin0° = 0).", "correct_answer": "D", "concept_tags": ["quarter-arc", "magnetic-field", "biot-savart-law"], "payload": {"question_id": "cuet-phy-mag-biot-11", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A quarter arc is one-fourth of the loop, giving μ₀I/(8R).", "misconception": "Using full loop formula for quarter arc"}, {"option_key": "B", "hint": "μ₀I/(4R) is the field due to a semicircular arc (half loop). A quarter arc gives half of this value: μ₀I/(8R).", "misconception": "Confusing semicircle with quarter circle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field of a long straight wire at distance R. The arc formula uses the angle subtended, not the straight-wire formula.", "misconception": "Applying straight wire formula to a curved conductor"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A comparison between Biot-Savart law and Coulomb''s law shows that both:", "explanation": "Both the Biot-Savart law (dB = μ₀Idl×r̂/(4πr²)) and Coulomb''s law (E = q r̂/(4πε₀r²)) exhibit an inverse-square dependence on distance. However, the Biot-Savart law involves a cross product (giving an angular dependence and a field perpendicular to the plane of dl and r), while Coulomb''s law produces a field along the line joining the source and point. Both also have a similar constant structure: μ₀/4π in Biot-Savart and 1/4πε₀ in Coulomb''s law.", "correct_answer": "D", "concept_tags": ["biot-savart-law", "coulomb-law", "comparison", "inverse-square"], "payload": {"question_id": "cuet-phy-mag-biot-12", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Produce fields along the line joining source and field point", "is_correct": false}, {"key": "B", "text": "Are valid only for static charges", "is_correct": false}, {"key": "C", "text": "Involve a dot product between source vector and displacement", "is_correct": false}, {"key": "D", "text": "Obey the inverse-square law of distance dependence", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law gives a field along the line joining source and point, but Biot-Savart law gives a field perpendicular to the plane containing dl and r (due to the cross product).", "misconception": "Assuming both laws give fields in the same direction relative to source"}, {"option_key": "B", "hint": "Biot-Savart law deals with moving charges (current), not static charges. Coulomb''s law is for static charges. They are not both valid for the same scenario.", "misconception": "Confusing the domain of applicability of the two laws"}, {"option_key": "C", "hint": "Biot-Savart law involves a cross product (dl × r̂), not a dot product. This is a key difference from Coulomb''s law.", "misconception": "Confusing cross product with dot product in Biot-Savart law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A wire carrying current I is bent into a circular arc of radius R subtending an angle of 60° at its centre. The magnitude of the magnetic field at the centre of the arc is:", "explanation": "The magnetic field at the centre of a circular arc subtending angle θ (in radians) is B = (μ₀I/2R)(θ/2π). For a 60° arc, θ = π/3 radians. Therefore B = (μ₀I/2R)(π/3)/(2π) = (μ₀I/2R)(1/6) = μ₀I/(12R).", "correct_answer": "A", "concept_tags": ["circular-arc", "magnetic-field-centre", "angle-subtended"], "payload": {"question_id": "cuet-phy-mag-biot-13", "subtopic": "Magnetic field at centre of arc/semicircle", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(12R)", "is_correct": true}, {"key": "B", "text": "μ₀I/(6R)", "is_correct": false}, {"key": "C", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "D", "text": "μ₀I/(2R)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This would be for a 120° arc (one-third of a full circle), not 60°.", "misconception": "Incorrectly computing the fraction of the circle"}, {"option_key": "C", "hint": "This is for a semicircular arc (180°), not 60°.", "misconception": "Confusing a 60° arc with a semicircle"}, {"option_key": "D", "hint": "This is for a full circular loop (360°). A 60° arc is only 1/6 of the full circle.", "misconception": "Using the full-loop formula without scaling by the arc fraction"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular loop of radius 0.1 m carries a current of 5 A. The magnetic field on the axis of the loop at a distance of 0.1 m from the centre is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "Using B = μ₀IR²/[2(R² + x²)^(3/2)] with R = 0.1 m, x = 0.1 m, I = 5 A: R² + x² = 0.01 + 0.01 = 0.02, so (R² + x²)^(3/2) = (0.02)^(3/2) = (0.02)^1 × √0.02 = 0.02 × 0.1414 = 2.828 × 10⁻³. Then B = (4π × 10⁻⁷ × 5 × 0.01)/(2 × 2.828 × 10⁻³) = (2π × 10⁻⁸)/(5.656 × 10⁻³) = 6.28 × 10⁻⁸/5.656 × 10⁻³ ≈ 1.11 × 10⁻⁵ T ≈ 11.1 μT.", "correct_answer": "A", "concept_tags": ["circular-loop", "axial-field", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-14", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "1.11 × 10⁻⁵ T", "is_correct": true}, {"key": "B", "text": "3.14 × 10⁻⁵ T", "is_correct": false}, {"key": "C", "text": "2.22 × 10⁻⁵ T", "is_correct": false}, {"key": "D", "text": "5.55 × 10⁻⁶ T", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the value of μ₀I/(2R) = the field at the centre. At x = R on the axis, the field is reduced by a factor of 1/(2√2) compared to the centre field.", "misconception": "Using centre formula instead of axial formula"}, {"option_key": "C", "hint": "This is exactly double the correct answer. Check the factor of 2 in the denominator of B = μ₀IR²/[2(R² + x²)^(3/2)].", "misconception": "Missing the factor of 2 in the denominator"}, {"option_key": "D", "hint": "This is half the correct answer. Check the evaluation of (R² + x²)^(3/2) carefully.", "misconception": "Error in computing (R² + x²)^(3/2)"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field at the centre of a semicircular wire of radius R carrying current I is:", "explanation": "A semicircular arc subtends an angle π at the centre. The field due to a circular arc subtending angle φ at the centre is B = μ₀Iφ/(4πR). For a semicircle, φ = π, so B = μ₀Iπ/(4πR) = μ₀I/(4R). The direction is perpendicular to the plane of the semicircle, determined by the right-hand rule.", "correct_answer": "B", "concept_tags": ["semicircular-arc", "magnetic-field", "biot-savart-law"], "payload": {"question_id": "cuet-phy-mag-biot-15", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀I/(2R)", "is_correct": false}, {"key": "B", "text": "μ₀I/(4R)", "is_correct": true}, {"key": "C", "text": "μ₀I/(2πR)", "is_correct": false}, {"key": "D", "text": "μ₀I/(8R)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀I/(2R) is the field at the centre of a full circular loop. A semicircle is half the loop, so its contribution is half: μ₀I/(4R).", "misconception": "Using full loop formula for semicircle"}, {"option_key": "C", "hint": "μ₀I/(2πR) is the field due to a long straight wire at distance R. The semicircular arc formula is μ₀I/(4R).", "misconception": "Confusing straight wire formula with arc formula"}, {"option_key": "D", "hint": "μ₀I/(8R) would be the field due to a quarter-circle arc, not a semicircle. A semicircle subtends angle π, giving μ₀I/(4R).", "misconception": "Using quarter-circle result instead of semicircle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A toroid has 500 turns, a mean radius of 0.2 m, and carries a current of 3 A. The magnetic field inside the toroid is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a toroid, applying Ampere''s law: B × 2πr = μ₀NI, so B = μ₀NI/(2πr). B = (4π × 10⁻⁷ × 500 × 3)/(2π × 0.2) = (4π × 1.5 × 10⁻⁴)/(0.4π) = (6π × 10⁻⁴)/(0.4π) = 6 × 10⁻⁴/0.4 = 1.5 × 10⁻³ T = 1.5 mT.", "correct_answer": "B", "concept_tags": ["toroid", "ampere-law", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-16", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "3.0 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "1.5 × 10⁻³ T", "is_correct": true}, {"key": "C", "text": "7.5 × 10⁻⁴ T", "is_correct": false}, {"key": "D", "text": "1.5 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is double the correct value. You may have used r = 0.1 m instead of the given mean radius r = 0.2 m in B = μ₀NI/(2πr).", "misconception": "Using radius instead of diameter, or halving the radius"}, {"option_key": "C", "hint": "This is half the correct answer. Check if you accidentally doubled the radius or halved the current in your calculation.", "misconception": "Arithmetic error in substitution"}, {"option_key": "D", "hint": "This is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 500 × 3 = 6π × 10⁻⁴, and dividing by 2π × 0.2 = 0.4π gives 1.5 × 10⁻³.", "misconception": "Power of 10 error in computation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A circular loop of radius R carries current I. At a large distance x (x >> R) along its axis, the magnetic field varies as:", "explanation": "The magnetic field on the axis of a circular loop is B = (μ₀IR²)/(2(R² + x²)^(3/2)). When x >> R, R² + x² ≈ x², so (R² + x²)^(3/2) ≈ x³. Therefore B ≈ μ₀IR²/(2x³), which shows B ∝ 1/x³. This is identical to the far-field behaviour of a magnetic dipole, where B ∝ 1/x³ along the axis.", "correct_answer": "D", "concept_tags": ["circular-loop-axis", "far-field", "magnetic-dipole"], "payload": {"question_id": "cuet-phy-mag-biot-17", "subtopic": "Magnetic field due to circular loop on axis", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "B ∝ 1/x", "is_correct": false}, {"key": "B", "text": "B ∝ 1/x²", "is_correct": false}, {"key": "C", "text": "B ∝ 1/x⁴", "is_correct": false}, {"key": "D", "text": "B ∝ 1/x³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1/x dependence applies to an infinite straight wire, not a circular loop at large distances.", "misconception": "Confusing straight-wire field with loop field"}, {"option_key": "B", "hint": "1/x² would be for a point charge electric field (Coulomb''s law). The loop behaves as a dipole with 1/x³.", "misconception": "Applying inverse-square law to a magnetic dipole"}, {"option_key": "C", "hint": "The exponent 3 comes from (x²)^(3/2) = x³. A 1/x⁴ dependence would require a quadrupole.", "misconception": "Overestimating the power in the far-field approximation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire is bent into a shape consisting of a semicircular arc of radius R connected to two straight segments, each extending radially from the ends of the arc to a point at distance 2R from the centre, and then connected by another semicircular arc of radius 2R (same centre). A current I flows through this composite loop. The magnetic field at the common centre is:", "explanation": "The straight radial segments contribute zero field at the centre because for them, dl is parallel to r̂ (sinθ = 0). The inner semicircle of radius R contributes B₁ = μ₀I/(4R) (using the semicircle formula μ₀I/(4R), directed out of the plane, say). The outer semicircle of radius 2R contributes B₂ = μ₀I/(4 × 2R) = μ₀I/(8R) in the opposite direction (since current flows in the opposite sense around the centre). Net field = μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), directed out of the plane.", "correct_answer": "C", "concept_tags": ["composite-loop", "semicircular-arcs", "superposition", "biot-savart-law"], "payload": {"question_id": "cuet-phy-mag-biot-18", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀I/(4R)", "is_correct": false}, {"key": "B", "text": "3μ₀I/(8R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/(8R), directed out of the plane", "is_correct": true}, {"key": "D", "text": "3μ₀I/(4R), directed into the plane", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is the field due to only the inner semicircular arc. You must also subtract the contribution of the outer semicircular arc, which opposes the inner one.", "misconception": "Ignoring the contribution of the outer semicircular arc"}, {"option_key": "B", "hint": "3μ₀I/(8R) would result from adding the two semicircular contributions instead of subtracting. The current traverses the two arcs in opposite senses relative to the centre, so the fields oppose each other.", "misconception": "Adding fields instead of subtracting due to opposite current directions"}, {"option_key": "D", "hint": "The magnitude and direction are both incorrect. The net field is μ₀I/(4R) − μ₀I/(8R) = μ₀I/(8R), and its direction is that of the larger contribution (inner arc).", "misconception": "Errors in both magnitude and direction determination"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A wire of length L carrying current I is bent into a regular hexagon. The magnetic field at the centre of the hexagon is:", "explanation": "A regular hexagon has 6 sides, each of length L/6. The perpendicular distance from the centre to each side is d = (L/6)(√3/2) = L√3/12. Each side subtends angles α = β = 30° at the foot of the perpendicular from the centre. The field due to one side at the centre is B₁ = (μ₀I/4πd)(sin30° + sin30°) = (μ₀I/4πd)(1) = μ₀I/(4πd). Substituting d = L√3/12: B₁ = μ₀I/(4π × L√3/12) = 12μ₀I/(4πL√3) = 3μ₀I/(πL√3) = √3μ₀I/(πL). For 6 sides, all fields point in the same direction, so B = 6B₁ = 6√3μ₀I/(πL).", "correct_answer": "B", "concept_tags": ["regular-polygon", "straight-conductor", "superposition"], "payload": {"question_id": "cuet-phy-mag-biot-19", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "3√3μ₀I/(πL)", "is_correct": false}, {"key": "B", "text": "6√3μ₀I/(πL)", "is_correct": true}, {"key": "C", "text": "2√3μ₀I/(πL)", "is_correct": false}, {"key": "D", "text": "12√3μ₀I/(πL)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This accounts for only 3 of the 6 sides. All six sides contribute equally and in the same direction.", "misconception": "Thinking opposite sides cancel each other"}, {"option_key": "C", "hint": "This would correspond to only 2 sides contributing. Recheck the multiplication factor.", "misconception": "Incorrect count of contributing sides"}, {"option_key": "D", "hint": "This is double the correct answer. Verify the field per side calculation carefully.", "misconception": "Error in computing the perpendicular distance to the centre"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two concentric coplanar circular loops have radii R and 2R. The smaller loop carries current I in the anticlockwise direction and the larger loop carries current 2I in the clockwise direction, as seen from the same side. The magnetic field at the common centre is:", "explanation": "Field due to smaller loop (anticlockwise, out of plane): B₁ = μ₀I/(2R), directed outward. Field due to larger loop (clockwise, into plane): B₂ = μ₀(2I)/(2 × 2R) = μ₀I/(2R), directed inward. Since B₁ and B₂ are equal in magnitude but opposite in direction, the net field at the centre is zero.", "correct_answer": "A", "concept_tags": ["concentric-loops", "superposition", "magnetic-field-direction"], "payload": {"question_id": "cuet-phy-mag-biot-20", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": true}, {"key": "B", "text": "μ₀I/(2R), directed out of the plane", "is_correct": false}, {"key": "C", "text": "μ₀I/R, directed into the plane", "is_correct": false}, {"key": "D", "text": "3μ₀I/(4R), directed out of the plane", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This ignores the contribution of the larger loop. Both loops contribute fields at the centre; you must find the vector sum. The two fields are equal and opposite, giving zero.", "misconception": "Considering only the smaller loop"}, {"option_key": "C", "hint": "The magnitudes are B₁ = μ₀I/(2R) (out) and B₂ = μ₀(2I)/(4R) = μ₀I/(2R) (in). These cancel out; they do not add to μ₀I/R.", "misconception": "Adding magnitudes instead of using vector directions"}, {"option_key": "D", "hint": "This does not correspond to any correct combination of the two fields. Compute each field using B = μ₀I/(2R) and apply superposition with correct directions.", "misconception": "Error in applying superposition principle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Both Biot-Savart law and Coulomb''s law are inverse-square laws, but the Biot-Savart law has an additional angle dependence through the cross product.\n\nReason (R): In Biot-Savart law, the magnetic field depends on sinθ (from dl × r̂), whereas in Coulomb''s law, the electric field has no such angular dependence for a point charge.", "explanation": "Both statements are correct. The Biot-Savart law dB = (μ₀/4π)(Idl × r̂)/r² is an inverse-square law like Coulomb''s law F = (1/4πε₀)(q₁q₂/r²)r̂, but it has an extra sinθ factor from the cross product. Coulomb''s law for a point charge is spherically symmetric with no angular dependence. Furthermore, R correctly explains why A is true: the cross product dl × r̂ introduces the sinθ factor that makes Biot-Savart angle-dependent, unlike Coulomb''s law.", "correct_answer": "A", "concept_tags": ["biot-savart-coulomb-comparison", "inverse-square-law", "angle-dependence"], "payload": {"question_id": "cuet-phy-mag-biot-25", "subtopic": "Comparison of Biot-Savart with Coulomb''s law", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains why Biot-Savart has angle dependence (sinθ from cross product) while Coulomb''s law does not. This is exactly the explanation for A.", "misconception": "Failing to see the causal link between R and A"}, {"option_key": "C", "hint": "R is factually correct: sinθ does arise from the cross product, and Coulomb''s law for a point charge has no angular dependence.", "misconception": "Incorrectly thinking Coulomb''s law has angular dependence"}, {"option_key": "D", "hint": "A is correct: Biot-Savart law is indeed an inverse-square law with additional angle dependence from the cross product.", "misconception": "Denying that Biot-Savart law is an inverse-square law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The magnetic field outside an ideal solenoid is zero. Reason (R): Applying Ampere''s circuital law to a rectangular Amperian loop with one side inside and one side outside the solenoid, the contribution from the outside segment is zero because the field there is zero.", "explanation": "Both Assertion and Reason are correct, and R is the correct explanation of A. For an ideal (infinitely long) solenoid, using Ampere''s law with a rectangular loop: ∮B·dl = B_inside × l + 0 + B_outside × l + 0 = μ₀nIl. Since the field is confined inside (by symmetry and superposition arguments), B_outside = 0, and B_inside = μ₀nI. The Reason correctly describes how Ampere''s law is applied with the field outside being zero.", "correct_answer": "A", "concept_tags": ["solenoid", "ampere-law", "ideal-solenoid", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-mag-biot-26", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The Reason directly describes the Amperian loop analysis that leads to the conclusion in the Assertion. It is not an unrelated fact; it is the specific explanation for why B = 0 outside.", "misconception": "Failing to see the direct causal link between Ampere''s law application and the result"}, {"option_key": "C", "hint": "The Reason is a correct description of how Ampere''s law is applied to an ideal solenoid. The zero field outside is both used as input (from symmetry) and confirmed by the law.", "misconception": "Incorrectly judging the Reason as false"}, {"option_key": "D", "hint": "The Assertion is well-established physics: an ideal infinite solenoid has zero external field. This is a standard NCERT result.", "misconception": "Incorrectly thinking a solenoid produces field outside"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The magnetic field at the centre of a current-carrying circular loop is always perpendicular to the plane of the loop.\n\nReason (R): According to Biot-Savart law, each current element of the loop contributes a field at the centre that lies in the plane of the loop.", "explanation": "Assertion A is correct: at the centre of a circular loop, every current element dl and the position vector r̂ (from the element to the centre) both lie in the plane of the loop. The cross product dl × r̂ is therefore perpendicular to this plane for every element. Since all contributions point in the same perpendicular direction, the net field is perpendicular to the plane. Reason R is incorrect: it states that each element''s contribution lies in the plane, but dl × r̂ is actually perpendicular to the plane, not in it.", "correct_answer": "C", "concept_tags": ["circular-loop-centre", "cross-product-direction", "biot-savart-application"], "payload": {"question_id": "cuet-phy-mag-biot-27", "subtopic": "Magnetic field due to circular loop at centre", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": true}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R claims dB lies in the plane, but dB = dl × r̂ is perpendicular to the plane since both dl and r̂ lie in the plane.", "misconception": "Confusing the plane of dl and r̂ with the direction of their cross product"}, {"option_key": "B", "hint": "R is not correct at all. The cross product of two in-plane vectors is always perpendicular to the plane.", "misconception": "Accepting R as correct without verifying the cross-product direction"}, {"option_key": "D", "hint": "A is definitely correct. The symmetry of the loop ensures all dB contributions add up perpendicular to the plane.", "misconception": "Doubting a well-established result about circular loop fields"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Biot-Savart law can be used to determine the magnetic field due to any arbitrary current distribution. Reason (R): Ampere''s circuital law can be conveniently used to calculate magnetic fields only when the system has sufficient symmetry.", "explanation": "Both A and R are correct statements. Biot-Savart law is a general law applicable to any current configuration (though integration may be complex). Ampere''s law, while always true, is practically useful for calculating B only in highly symmetric situations (infinite straight wire, solenoid, toroid). However, R is NOT the explanation for A. The reason Biot-Savart law is general is because it directly integrates the contribution of each current element, not because Ampere''s law has symmetry limitations.", "correct_answer": "B", "concept_tags": ["biot-savart-law", "ampere-law", "symmetry", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-mag-biot-28", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "evaluate", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While both statements are true, the limitation of Ampere''s law (needing symmetry) does not explain why Biot-Savart law is general. They are independent facts about two different laws.", "misconception": "Assuming that one law''s limitation automatically explains another law''s generality"}, {"option_key": "C", "hint": "The Reason is a correct statement. Ampere''s law is indeed only practically useful for field calculation when high symmetry exists (e.g., infinite wire, solenoid, toroid).", "misconception": "Thinking Ampere''s law always allows easy field computation"}, {"option_key": "D", "hint": "The Assertion is correct. Biot-Savart law is indeed a general law that can be applied to any current distribution by integrating dB contributions from each element.", "misconception": "Thinking Biot-Savart law has limited applicability"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Long straight conductor carrying current I\n(Q) Circular loop of radius R at its centre\n(R) Solenoid with n turns per unit length\n(S) Toroid of mean radius r with N total turns\n\nColumn II:\n(1) B = μ₀nI\n(2) B = μ₀I/(2πd)\n(3) B = μ₀NI/(2πr)\n(4) B = μ₀I/(2R)", "explanation": "P-2: A long straight conductor produces B = μ₀I/(2πd) at perpendicular distance d. Q-4: At the centre of a circular loop, B = μ₀I/(2R). R-1: Inside an ideal solenoid, B = μ₀nI. S-3: Inside a toroid, B = μ₀NI/(2πr). The correct matching is P-2, Q-4, R-1, S-3.", "correct_answer": "C", "concept_tags": ["magnetic-field-formulas", "straight-conductor", "circular-loop", "solenoid", "toroid"], "payload": {"question_id": "cuet-phy-mag-biot-29", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "B", "text": "P-2, Q-3, R-1, S-4", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-1, S-3", "is_correct": true}, {"key": "D", "text": "P-3, Q-4, R-1, S-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P-1 would assign B = μ₀nI to a straight conductor, but that is the solenoid formula. A straight conductor gives B = μ₀I/(2πd).", "misconception": "Confusing solenoid formula with straight wire formula"}, {"option_key": "B", "hint": "Q-3 assigns the toroid formula to the circular loop. The circular loop at centre gives B = μ₀I/(2R), not μ₀NI/(2πr).", "misconception": "Swapping circular loop and toroid formulas"}, {"option_key": "D", "hint": "P-3 assigns the toroid formula to a straight conductor and S-2 assigns the straight wire formula to the toroid. These are swapped.", "misconception": "Interchanging straight conductor and toroid formulas"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match Column I with Column II:\n\nColumn I:\n(P) Magnetic field on the axis of a circular loop at distance x >> R from centre\n(Q) Magnetic field at the centre of a circular arc subtending angle θ\n(R) Magnetic field inside a solenoid at a point near its end\n(S) Magnetic field at the centre of two concentric coplanar loops of radii R and 2R carrying equal current I in the same direction\n\nColumn II:\n(1) μ₀Iθ/(4πR)\n(2) Approximately μ₀nI/2\n(3) 3μ₀I/(4R)\n(4) Varies as 1/x³ (magnetic dipole behaviour)", "explanation": "P-4: For x >> R, B = μ₀IR²/[2(R² + x²)^(3/2)] ≈ μ₀IR²/(2x³), which varies as 1/x³ like a magnetic dipole. Q-1: The field at the centre of an arc of angle θ is B = μ₀Iθ/(4πR). R-2: At the end of a solenoid, the field is approximately half the interior value, i.e., ≈μ₀nI/2. S-3: B = μ₀I/(2R) + μ₀I/(2×2R) = μ₀I/(2R) + μ₀I/(4R) = 3μ₀I/(4R).", "correct_answer": "D", "concept_tags": ["axial-field", "magnetic-dipole", "arc-formula", "solenoid-end", "superposition"], "payload": {"question_id": "cuet-phy-mag-biot-30", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-4, Q-1, R-3, S-2", "is_correct": false}, {"key": "B", "text": "P-1, Q-4, R-2, S-3", "is_correct": false}, {"key": "C", "text": "P-4, Q-3, R-2, S-1", "is_correct": false}, {"key": "D", "text": "P-4, Q-1, R-2, S-3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "R-3 assigns 3μ₀I/(4R) to the solenoid end field, but that expression involves R (loop radius), not the solenoid parameters. The solenoid end field is ≈μ₀nI/2.", "misconception": "Confusing solenoid end field with concentric loop superposition"}, {"option_key": "B", "hint": "P-1 assigns the arc formula to the far-axis field. The far-axis field follows the dipole 1/x³ dependence, not the arc formula.", "misconception": "Mixing up axial field behaviour with arc field formula"}, {"option_key": "C", "hint": "Q-3 assigns 3μ₀I/(4R) to an arc, but that result comes from superposition of two concentric loops, not a single arc. The arc formula is μ₀Iθ/(4πR).", "misconception": "Confusing arc formula with superposition result"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The Biot-Savart law, like Coulomb''s law, obeys the principle of superposition, meaning the total magnetic field at a point due to several current-carrying conductors is the vector sum of the fields produced by each conductor individually.", "explanation": "This statement is TRUE. The principle of superposition applies to both electric and magnetic fields. The total magnetic field at any point due to multiple current sources is obtained by taking the vector sum of the individual magnetic fields produced by each source. This is a fundamental property used extensively in calculating magnetic fields of complex current configurations.", "correct_answer": "A", "concept_tags": ["superposition-principle", "biot-savart-law", "vector-addition"], "payload": {"question_id": "cuet-phy-mag-biot-31", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Superposition is valid for all electromagnetic fields in free space. Magnetic fields from different sources add vectorially.", "misconception": "Thinking superposition fails for magnetic fields"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid is uniform and parallel to the axis of the solenoid.", "explanation": "This is TRUE. By applying Ampere''s circuital law to an ideal (infinitely long) solenoid, the magnetic field inside is found to be B = μ₀nI, which is constant and does not depend on the position inside the solenoid. The field is directed along the axis of the solenoid, as determined by the right-hand rule. Outside the ideal solenoid, the field is zero.", "correct_answer": "A", "concept_tags": ["solenoid", "uniform-field", "ampere-law"], "payload": {"question_id": "cuet-phy-mag-biot-32", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The statement is a well-known result from Ampere''s law. The field B = μ₀nI is independent of position inside the solenoid and is directed along the axis.", "misconception": "Thinking the field varies inside a solenoid or is not axial"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field due to an infinitely long straight wire carrying current I varies inversely as the square of the perpendicular distance from the wire (B ∝ 1/d²).", "explanation": "This statement is FALSE. The magnetic field due to an infinitely long straight current-carrying wire is B = μ₀I/(2πd), which shows that B varies inversely as the first power of distance (B ∝ 1/d), not as the square of the distance. The inverse-square dependence (1/r²) appears in Coulomb''s law for a point charge, not in the magnetic field of an infinite wire.", "correct_answer": "B", "concept_tags": ["infinite-wire", "distance-dependence", "inverse-distance"], "payload": {"question_id": "cuet-phy-mag-biot-33", "subtopic": "Infinite straight wire", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Recall B = μ₀I/(2πd) for an infinite wire. The d is in the first power in the denominator, not squared.", "misconception": "Confusing the 1/r² in Biot-Savart law (for a point element) with the integrated result for an infinite wire"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The magnetic field at a point on the axis of a current-carrying circular loop is always perpendicular to the axis of the loop.", "explanation": "This is FALSE. The magnetic field at any point on the axis of a current-carrying circular loop is directed along the axis of the loop (either towards or away from the loop depending on current direction), not perpendicular to it. By symmetry, the perpendicular components from opposite current elements cancel out, leaving only the axial component. The field is given by B = μ₀IR²/[2(R² + x²)^(3/2)] along the axis.", "correct_answer": "B", "concept_tags": ["circular-loop", "axial-field", "symmetry", "field-direction"], "payload": {"question_id": "cuet-phy-mag-biot-34", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field on the axis is along the axis, not perpendicular to it. By symmetry, the perpendicular components cancel. Think of the right-hand thumb rule: curling fingers in the direction of current, the thumb points along the axis.", "misconception": "Confusing axial direction with perpendicular direction for on-axis field"}, {"option_key": "C", "hint": "This option is not applicable for this question.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for this question.", "misconception": null}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "A circular coil of radius 0.1 m carrying a current of 3.14 A has ________ turns if the magnetic field at its centre is 2 × 10⁻⁵ T. (Use μ₀ = 4π × 10⁻⁷ T·m/A and π = 3.14)", "explanation": "The magnetic field at the centre of a coil with N turns is B = μ₀NI/(2R). Solving for N: N = 2BR/(μ₀I) = 2 × (2 × 10⁻⁵) × 0.1 / (4π × 10⁻⁷ × 3.14) = (4 × 10⁻⁶) / (4 × 3.14 × 3.14 × 10⁻⁷) = (4 × 10⁻⁶) / (39.44 × 10⁻⁷) = (4 × 10⁻⁶) / (3.944 × 10⁻⁶) ≈ 1. Wait, let me recalculate: N = 2 × 2×10⁻⁵ × 0.1 / (4π × 10⁻⁷ × 3.14) = 4×10⁻⁶ / (4 × 3.14 × 10⁻⁷ × 3.14) = 4×10⁻⁶ / (3.944 × 10⁻⁶) ≈ 1. Actually: μ₀I = 4π × 10⁻⁷ × 3.14 = 4 × 3.14 × 3.14 × 10⁻⁷ = 39.44 × 10⁻⁷. 2BR = 2 × 2×10⁻⁵ × 0.1 = 4 × 10⁻⁶. N = 4×10⁻⁶ / 39.44×10⁻⁷ = 4×10⁻⁶ / 3.944×10⁻⁶ ≈ 1. So N = 1 turn. The answer is B (1 turn).", "correct_answer": "B", "concept_tags": ["circular-coil", "number-of-turns", "magnetic-field-centre"], "payload": {"question_id": "cuet-phy-mag-biot-35", "subtopic": "Magnetic field due to circular loop at centre", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "2", "is_correct": false}, {"key": "B", "text": "1", "is_correct": true}, {"key": "C", "text": "5", "is_correct": false}, {"key": "D", "text": "10", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Substitute the values carefully. N = 2BR/(μ₀I). With the given numbers, N comes out to approximately 1.", "misconception": "Arithmetic error in calculation"}, {"option_key": "C", "hint": "This would give a much larger field at the centre. Check your powers of 10.", "misconception": "Error in handling powers of 10"}, {"option_key": "D", "hint": "10 turns would produce a field 10 times larger than what is given.", "misconception": "Forgetting to divide by the correct factor"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "If a circular coil of 200 turns and radius 0.05 m carries a current of 0.5 A, the magnetic field at its centre is _____ T. (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a flat coil of N turns, the magnetic field at the centre is B = μ₀NI/(2R). Substituting: B = (4π × 10⁻⁷ × 200 × 0.5)/(2 × 0.05) = (4π × 10⁻⁷ × 100)/0.1 = (4π × 10⁻⁵)/0.1 = 4π × 10⁻⁴ = 12.57 × 10⁻⁴ T ≈ 1.26 × 10⁻³ T.", "correct_answer": "C", "concept_tags": ["circular-coil", "multiple-turns", "magnetic-field-centre", "numerical-problem"], "payload": {"question_id": "cuet-phy-mag-biot-36", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "6.28 × 10⁻³", "is_correct": false}, {"key": "B", "text": "1.26 × 10⁻⁴", "is_correct": false}, {"key": "C", "text": "1.26 × 10⁻³", "is_correct": true}, {"key": "D", "text": "6.28 × 10⁻⁴", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "6.28 × 10⁻³ is five times too large. Check if you used the correct radius: R = 0.05 m, not 0.01 m.", "misconception": "Using incorrect radius value"}, {"option_key": "B", "hint": "1.26 × 10⁻⁴ is off by a factor of 10. Recheck: μ₀NI = 4π × 10⁻⁷ × 200 × 0.5 = 4π × 10⁻⁵, and dividing by 2R = 0.1 gives 4π × 10⁻⁴ ≈ 1.26 × 10⁻³.", "misconception": "Power of 10 error"}, {"option_key": "D", "hint": "6.28 × 10⁻⁴ = 2π × 10⁻⁴, which suggests using N = 100 or I = 0.25. With the given values, B = 4π × 10⁻⁴ ≈ 1.26 × 10⁻³ T.", "misconception": "Halving one of the given quantities"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "An MRI (Magnetic Resonance Imaging) machine uses a large solenoid to produce a strong, uniform magnetic field for medical imaging. A particular MRI solenoid is 2 m long, has 10,000 turns, and produces a magnetic field of 1.5 T inside. What is the current flowing through the solenoid? (μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "For a solenoid, B = μ₀nI, where n = N/L = 10000/2 = 5000 turns/m. Rearranging for current: I = B/(μ₀n) = 1.5/(4π × 10⁻⁷ × 5000) = 1.5/(2π × 10⁻³) = 1.5/(6.283 × 10⁻³) ≈ 238.7 A ≈ 239 A. This illustrates why MRI machines require superconducting coils to sustain such large currents without resistive heating.", "correct_answer": "D", "concept_tags": ["solenoid", "MRI-application", "ampere-law", "numerical-problem", "real-world"], "payload": {"question_id": "cuet-phy-mag-biot-37", "subtopic": "Biot-Savart Law and Applications", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "apply", "options": [{"key": "A", "text": "23.9 A", "is_correct": false}, {"key": "B", "text": "119 A", "is_correct": false}, {"key": "C", "text": "477 A", "is_correct": false}, {"key": "D", "text": "239 A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "23.9 A is ten times too small. Check n = N/L = 10000/2 = 5000 turns/m, not 50000. Then I = 1.5/(4π × 10⁻⁷ × 5000) ≈ 239 A.", "misconception": "Error in calculating turns per unit length"}, {"option_key": "B", "hint": "119 A is half the correct answer. This could result from using L = 1 m instead of 2 m (making n = 10000 instead of 5000), then dividing again incorrectly.", "misconception": "Using incorrect length or extra factor of 2"}, {"option_key": "C", "hint": "477 A is double the correct answer, suggesting n = N/L was calculated as 2500 instead of 5000, or an error in length. Use L = 2 m to get n = 5000.", "misconception": "Halving the turns per unit length"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "At what approximate distance along the x-axis from the origin does the net magnetic field become zero, given that both the straight wire and the circular loop produce fields in opposite directions along the positive x-axis? (Use μ₀ = 4π × 10⁻⁷ T·m/A)", "explanation": "The magnetic field due to the straight wire at distance x on the x-axis is B_wire = μ₀I₁/(2πx) = μ₀(5)/(2πx). The field due to the circular loop on its axis at distance x is B_loop = μ₀I₂R²/(2(R² + x²)^(3/2)) = μ₀(2)(0.05)²/(2(0.0025 + x²)^(3/2)). Setting B_wire = B_loop and simplifying: 5/(2πx) = 2(0.0025)/(2(0.0025 + x²)^(3/2)). For x >> R (far field), B_loop ≈ μ₀(2)(0.0025)/(2x³). So 5/(2πx) = 0.0025/x³, giving x² = 0.0025 × 2π/5 = 0.00314, so x ≈ 0.056 m ≈ 0.06 m. Among the options, 0.06 m is closest.", "correct_answer": "B", "concept_tags": ["superposition", "null-point", "straight-wire", "circular-loop-axis"], "payload": {"question_id": "cuet-phy-mag-biot-38", "subtopic": "Superposition of magnetic fields", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "0.03 m", "is_correct": false}, {"key": "B", "text": "0.06 m", "is_correct": true}, {"key": "C", "text": "0.10 m", "is_correct": false}, {"key": "D", "text": "0.15 m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At 0.03 m (close to the loop radius), the loop field dominates and the far-field approximation is not valid. The null point is farther out.", "misconception": "Underestimating the distance where fields balance"}, {"option_key": "C", "hint": "At 0.10 m, the loop field drops as 1/x³ while the wire field drops as 1/x, so the wire field dominates and they cannot be equal here.", "misconception": "Overestimating the null-point distance"}, {"option_key": "D", "hint": "At such large distance, the loop field is negligible compared to the wire field. The null point must be closer.", "misconception": "Not recognizing the rapid decay of dipole fields"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps in the correct order for deriving the magnetic field at the centre of a circular current-carrying loop using Biot-Savart law.", "explanation": "The derivation proceeds as follows: (Step 2) Start by considering a small current element and applying Biot-Savart law. (Step 5) Recognise that the distance r from any element to the centre equals R. (Step 1) Note that dl is perpendicular to r̂ at the centre, so the cross product magnitude simplifies. (Step 4) Integrate over the full loop, substituting the simplified expressions. (Step 3) Evaluate the integral to obtain the final result B = μ₀I/(2R).", "correct_answer": "D", "concept_tags": ["biot-savart-derivation", "circular-loop", "integration"], "payload": {"question_id": "cuet-phy-mag-biot-39", "subtopic": "Magnetic field due to circular loop at centre", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "understand", "options": [{"key": "A", "text": "1 → 2 → 5 → 4 → 3", "is_correct": false}, {"key": "B", "text": "2 → 1 → 5 → 3 → 4", "is_correct": false}, {"key": "C", "text": "5 → 2 → 1 → 4 → 3", "is_correct": false}, {"key": "D", "text": "2 → 5 → 1 → 4 → 3", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "You must first write the Biot-Savart law (step 2) before noting the perpendicularity (step 1).", "misconception": "Applying geometric simplification before stating the law"}, {"option_key": "B", "hint": "Integration (step 4) must come before the final result (step 3), and geometric observations (step 5) before cross-product simplification (step 1).", "misconception": "Jumbling the order of simplification and integration"}, {"option_key": "C", "hint": "You should state the Biot-Savart law (step 2) before identifying the constant distance (step 5), since the law defines what r represents.", "misconception": "Identifying geometric properties before stating the governing law"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-biot", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following current-carrying configurations in order of increasing magnetic field strength at the specified point, from weakest to strongest. All carry the same current I and have the same characteristic dimension R.", "explanation": "The magnetic field at the centre of curvature of a circular arc subtending angle θ is B = μ₀Iθ/(4πR). For a quarter circle (θ = π/2): B = μ₀I/(8R). For a semicircle (θ = π): B = μ₀I/(4R). For a three-quarter arc (θ = 3π/2): B = 3μ₀I/(8R). For a full circle (θ = 2π): B = μ₀I/(2R). Ordering from weakest to strongest: quarter < semicircle < three-quarter < full circle, i.e., 1 → 3 → 4 → 2.", "correct_answer": "A", "concept_tags": ["circular-arc", "field-comparison", "proportionality-to-angle"], "payload": {"question_id": "cuet-phy-mag-biot-40", "subtopic": "Magnetic field at centre of arc/semicircle", "topic_name": "Biot-Savart Law and Applications", "bloom_level": "analyze", "options": [{"key": "A", "text": "1 → 3 → 4 → 2", "is_correct": true}, {"key": "B", "text": "2 → 4 → 3 → 1", "is_correct": false}, {"key": "C", "text": "1 → 3 → 2 → 4", "is_correct": false}, {"key": "D", "text": "3 → 1 → 4 → 2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the reverse order (strongest to weakest). The question asks for weakest to strongest.", "misconception": "Reading the question as strongest to weakest"}, {"option_key": "C", "hint": "A full circle (2) has a larger field than a three-quarter arc (4), since it subtends a larger angle.", "misconception": "Thinking 3/4 arc produces a stronger field than a full loop"}, {"option_key": "D", "hint": "A quarter-circle (1) produces a weaker field than a semicircle (3), since π/2 < π.", "misconception": "Incorrectly ranking quarter-circle above semicircle"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law relates the line integral of magnetic field around a closed loop to:", "explanation": "Ampere''s circuital law states ∮B⃗·dl⃗ = μ₀I_enclosed. The line integral of the magnetic field B⃗ around any closed Amperian loop equals μ₀ times the net current enclosed by that loop.", "correct_answer": "A", "concept_tags": ["ampere-law-statement", "line-integral", "enclosed-current"], "payload": {"question_id": "cuet-phy-mag-ampere-01", "subtopic": "Ampere''s law statement", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀ times the net current enclosed by the loop", "is_correct": true}, {"key": "B", "text": "The total magnetic flux through the loop", "is_correct": false}, {"key": "C", "text": "The electric field inside the loop", "is_correct": false}, {"key": "D", "text": "The total current in the external circuit", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Magnetic flux is the surface integral ∫B⃗·dA⃗, not the line integral ∮B⃗·dl⃗.", "misconception": "Confusing line integral with surface integral"}, {"option_key": "C", "hint": "Ampere''s law deals with magnetic field B⃗, not electric field E⃗.", "misconception": "Mixing up electric and magnetic field laws"}, {"option_key": "D", "hint": "Only the current passing through the area bounded by the Amperian loop matters, not the total circuit current.", "misconception": "Using total circuit current instead of enclosed current"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of the line integral ∮B⃗·dl⃗ in Ampere''s circuital law is:", "explanation": "The line integral ∮B⃗·dl⃗ has the unit of B (Tesla) × l (metre) = T·m. Since T = kg·s⁻²·A⁻¹, the unit becomes kg·m·s⁻²·A⁻¹, which is the same as the unit of μ₀I (T·m/A × A = T·m).", "correct_answer": "B", "concept_tags": ["line-integral", "units", "ampere-law"], "payload": {"question_id": "cuet-phy-mag-ampere-02", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "Tesla", "is_correct": false}, {"key": "B", "text": "Tesla·metre", "is_correct": true}, {"key": "C", "text": "Tesla/metre", "is_correct": false}, {"key": "D", "text": "Weber", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Tesla is the unit of B alone. The line integral multiplies B by dl, adding a metre to the unit.", "misconception": "Forgetting the dl contribution in the integral"}, {"option_key": "C", "hint": "Tesla/metre would arise from dB/dl, not B·dl. Integration multiplies units, not divides.", "misconception": "Confusing differentiation with integration units"}, {"option_key": "D", "hint": "Weber (Wb) is the unit of magnetic flux Φ = ∫B⃗·dA⃗ (T·m²), not the line integral (T·m).", "misconception": "Confusing line integral with surface integral units"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "An Amperian loop is drawn in a region where no current passes through the loop. The value of ∮B⃗·dl⃗ for this loop is:", "explanation": "By Ampere''s circuital law, ∮B⃗·dl⃗ = μ₀I_enclosed. If no current threads through the Amperian loop, I_enclosed = 0, so ∮B⃗·dl⃗ = 0. Note that B⃗ itself need not be zero at every point on the loop; only the line integral around the closed loop is zero.", "correct_answer": "C", "concept_tags": ["amperian-loop", "zero-enclosed-current", "line-integral"], "payload": {"question_id": "cuet-phy-mag-ampere-03", "subtopic": "Amperian loop", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "μ₀", "is_correct": false}, {"key": "B", "text": "Infinity", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "Cannot be determined without knowing B⃗", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀ alone has no physical meaning here. ∮B⃗·dl⃗ = μ₀ × 0 = 0 when no current is enclosed.", "misconception": "Thinking μ₀ appears even with zero enclosed current"}, {"option_key": "B", "hint": "The line integral is always finite. With zero enclosed current it equals zero.", "misconception": "Misunderstanding the nature of the line integral"}, {"option_key": "D", "hint": "Ampere''s law directly gives the result: ∮B⃗·dl⃗ = μ₀I_enc = 0. No additional information about B⃗ is needed.", "misconception": "Not recognizing that the law gives a direct answer for the line integral"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Ampere''s circuital law is analogous to which law in electrostatics?", "explanation": "Ampere''s circuital law (∮B⃗·dl⃗ = μ₀I_enc) is the magnetic analogue of Gauss''s law in electrostatics (∮E⃗·dA⃗ = Q_enc/ε₀). Both relate a field integral to an enclosed source (current or charge) and are most useful in situations of high symmetry.", "correct_answer": "D", "concept_tags": ["ampere-law", "gauss-law", "analogy"], "payload": {"question_id": "cuet-phy-mag-ampere-04", "subtopic": "Comparison with Gauss''s law", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Coulomb''s law", "is_correct": false}, {"key": "B", "text": "Faraday''s law", "is_correct": false}, {"key": "C", "text": "Biot-Savart law", "is_correct": false}, {"key": "D", "text": "Gauss''s law", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law gives force between charges. Its magnetic analogue is the Biot-Savart law, not Ampere''s law.", "misconception": "Confusing Coulomb''s law analogy with Gauss''s law analogy"}, {"option_key": "B", "hint": "Faraday''s law relates changing magnetic flux to induced EMF. It is not the electrostatic analogue of Ampere''s law.", "misconception": "Mixing electromagnetic induction with magnetostatics"}, {"option_key": "C", "hint": "Biot-Savart law is analogous to Coulomb''s law (both give field due to a source element). Ampere''s law is analogous to Gauss''s law.", "misconception": "Confusing Biot-Savart analogy with Ampere''s law analogy"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "For applying Ampere''s circuital law to find the magnetic field inside a long solenoid, the ideal Amperian loop is:", "explanation": "To exploit the symmetry of a solenoid, we choose a rectangular Amperian loop with one side inside the solenoid (parallel to the axis) and the opposite side outside where B ≈ 0. The two short sides are perpendicular to B, contributing zero. This gives B·L = μ₀nLI, hence B = μ₀nI.", "correct_answer": "B", "concept_tags": ["solenoid", "amperian-loop", "rectangular-loop"], "payload": {"question_id": "cuet-phy-mag-ampere-05", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "A circular loop concentric with the solenoid", "is_correct": false}, {"key": "B", "text": "A rectangular loop partially inside and partially outside the solenoid", "is_correct": true}, {"key": "C", "text": "A triangular loop inside the solenoid", "is_correct": false}, {"key": "D", "text": "A spherical surface enclosing the solenoid", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "A circular loop would not exploit the translational symmetry along the solenoid axis. The field inside is uniform and axial, requiring a rectangular loop.", "misconception": "Using the wrong symmetry for the Amperian loop"}, {"option_key": "C", "hint": "A triangular loop offers no symmetry advantage. The rectangular loop aligns sides parallel and perpendicular to B⃗.", "misconception": "Arbitrary loop shape without symmetry consideration"}, {"option_key": "D", "hint": "A spherical surface is used in Gauss''s law (surface integral), not Ampere''s law (line integral).", "misconception": "Confusing Gauss''s law surface with Amperian loop"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The magnetic field inside an ideal solenoid with n turns per unit length carrying current I is:", "explanation": "Using Ampere''s circuital law with a rectangular Amperian loop, the field inside an ideal (infinite) solenoid is B = μ₀nI. This field is uniform throughout the interior and directed along the axis of the solenoid.", "correct_answer": "A", "concept_tags": ["solenoid", "magnetic-field-formula", "ampere-law-application"], "payload": {"question_id": "cuet-phy-mag-ampere-06", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀nI", "is_correct": true}, {"key": "B", "text": "μ₀nI/2π", "is_correct": false}, {"key": "C", "text": "μ₀NI", "is_correct": false}, {"key": "D", "text": "μ₀I/2πr", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The 2π factor appears for an infinite straight wire, not a solenoid. Inside a solenoid B = μ₀nI with no 2π denominator.", "misconception": "Mixing solenoid formula with straight wire formula"}, {"option_key": "C", "hint": "N is the total number of turns. The correct formula uses n = N/L (turns per unit length), giving B = μ₀nI.", "misconception": "Using total turns N instead of turns per unit length n"}, {"option_key": "D", "hint": "This is the formula for the magnetic field around an infinite straight wire, not inside a solenoid.", "misconception": "Applying the wrong formula for the geometry"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A long straight wire carries a current of 5 A. Using Ampere''s circuital law, the magnetic field at a distance of 10 cm from the wire is (μ₀ = 4π × 10⁻⁷ T·m/A):", "explanation": "For a long straight wire, choosing a circular Amperian loop of radius r = 0.1 m: ∮B⃗·dl⃗ = B(2πr) = μ₀I. So B = μ₀I/(2πr) = (4π × 10⁻⁷ × 5)/(2π × 0.1) = (20π × 10⁻⁷)/(0.2π) = 10⁻⁵ T = 10 μT.", "correct_answer": "C", "concept_tags": ["infinite-wire", "numerical", "ampere-law-application"], "payload": {"question_id": "cuet-phy-mag-ampere-07", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1 × 10⁻⁶ T", "is_correct": false}, {"key": "B", "text": "1 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "1 × 10⁻⁵ T", "is_correct": true}, {"key": "D", "text": "2 × 10⁻⁵ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is off by a factor of 10. Check: (4π × 10⁻⁷ × 5)/(2π × 0.1) = 10⁻⁵ T, not 10⁻⁶ T.", "misconception": "Error in powers of ten during calculation"}, {"option_key": "B", "hint": "This is 10 times too large. Ensure you converted 10 cm to 0.1 m properly in the denominator.", "misconception": "Not converting cm to m"}, {"option_key": "D", "hint": "This would correspond to I = 10 A or r = 5 cm. With I = 5 A and r = 10 cm, B = 10⁻⁵ T.", "misconception": "Arithmetic error in the final calculation"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A solenoid of length 50 cm has 500 turns and carries a current of 2 A. The magnetic field inside the solenoid is approximately:", "explanation": "Number of turns per unit length n = N/L = 500/0.5 = 1000 turns/m. Using B = μ₀nI = 4π × 10⁻⁷ × 1000 × 2 = 8π × 10⁻⁴ ≈ 2.51 × 10⁻³ T ≈ 2.5 mT.", "correct_answer": "D", "concept_tags": ["solenoid", "numerical", "turns-per-unit-length"], "payload": {"question_id": "cuet-phy-mag-ampere-08", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1.26 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "6.28 × 10⁻⁴ T", "is_correct": false}, {"key": "C", "text": "1.26 × 10⁻² T", "is_correct": false}, {"key": "D", "text": "2.51 × 10⁻³ T", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This would correspond to I = 1 A instead of 2 A. The correct value is 8π × 10⁻⁴ ≈ 2.51 × 10⁻³ T.", "misconception": "Forgetting to multiply by the current value"}, {"option_key": "B", "hint": "This is too small. Check n = 500/0.5 = 1000/m, then B = 4π × 10⁻⁷ × 1000 × 2 = 2.51 × 10⁻³ T.", "misconception": "Incorrectly calculating n by using length in cm"}, {"option_key": "C", "hint": "This is 10 times too large. Verify: 4π × 10⁻⁷ × 10³ × 2 = 8π × 10⁻⁴ ≈ 2.51 × 10⁻³ T.", "misconception": "Error in powers of ten"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a toroid with N total turns, mean radius R, and carrying current I, the magnetic field inside the toroid at the mean radius is:", "explanation": "For a toroid, using a circular Amperian loop of radius R inside the toroid: ∮B⃗·dl⃗ = B(2πR) = μ₀NI. Therefore B = μ₀NI/(2πR). Unlike a solenoid, the field inside a toroid depends on the radial position.", "correct_answer": "B", "concept_tags": ["toroid", "magnetic-field-formula", "ampere-law-application"], "payload": {"question_id": "cuet-phy-mag-ampere-09", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀NI", "is_correct": false}, {"key": "B", "text": "μ₀NI/(2πR)", "is_correct": true}, {"key": "C", "text": "μ₀nI (where n = N/2πR)", "is_correct": false}, {"key": "D", "text": "Both B and C", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This would be the result if 2πR were absent. The Amperian loop has circumference 2πR, so B = μ₀NI/(2πR).", "misconception": "Forgetting the loop circumference factor"}, {"option_key": "C", "hint": "While n = N/(2πR) gives the same numerical result, the standard form is B = μ₀NI/(2πR). Option C writes the formula differently but is not wrong in value — however option D says ''Both B and C'' which makes C alone incorrect as an answer.", "misconception": "Not recognizing the standard form of the toroid formula"}, {"option_key": "D", "hint": "While B and C give the same numerical value, the question asks for the field expression in standard form. B = μ₀NI/(2πR) is the direct result from Ampere''s law. Since C is just a rewrite, the primary answer is B.", "misconception": "Thinking both equivalent forms should be the answer when only the standard form is asked"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A circular Amperian loop of radius r is drawn concentric with a long straight wire carrying current I. If the radius is doubled to 2r, the value of ∮B⃗·dl⃗ will:", "explanation": "By Ampere''s law, ∮B⃗·dl⃗ = μ₀I_enclosed. The enclosed current remains I regardless of the loop radius (as long as the wire passes through it). Therefore, the line integral remains unchanged at μ₀I even when the radius is doubled.", "correct_answer": "A", "concept_tags": ["amperian-loop", "enclosed-current", "line-integral-independence"], "payload": {"question_id": "cuet-phy-mag-ampere-10", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Remain the same", "is_correct": true}, {"key": "B", "text": "Become half", "is_correct": false}, {"key": "C", "text": "Become double", "is_correct": false}, {"key": "D", "text": "Become four times", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "While B becomes half (B ∝ 1/r), the circumference doubles (2πr → 4πr). The product B × 2πr = μ₀I remains unchanged.", "misconception": "Thinking the line integral changes because B changes"}, {"option_key": "C", "hint": "The line integral depends only on I_enclosed, not on the loop size. ∮B⃗·dl⃗ = μ₀I regardless of r.", "misconception": "Confusing the integral with circumference alone"}, {"option_key": "D", "hint": "The line integral is independent of the loop radius. It equals μ₀I for any loop enclosing the wire.", "misconception": "Incorrectly applying area dependence to line integral"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The magnetic field outside an ideal infinite solenoid is:", "explanation": "Using Ampere''s circuital law with a rectangular loop entirely outside the solenoid: since no net current is enclosed (currents on both sides cancel), ∮B⃗·dl⃗ = 0, implying B_outside = 0. This is a key result — the field of an ideal infinite solenoid is entirely confined to its interior.", "correct_answer": "C", "concept_tags": ["solenoid", "field-outside", "zero-field"], "payload": {"question_id": "cuet-phy-mag-ampere-11", "subtopic": "Application to solenoid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "remember", "options": [{"key": "A", "text": "μ₀nI", "is_correct": false}, {"key": "B", "text": "μ₀nI/2", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "Depends on the distance from the solenoid", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "μ₀nI is the field inside the solenoid. Outside an ideal infinite solenoid, the field is zero.", "misconception": "Confusing inside and outside fields"}, {"option_key": "B", "hint": "There is no half-value region. The field is μ₀nI inside and zero outside.", "misconception": "Incorrectly averaging fields"}, {"option_key": "D", "hint": "For an ideal infinite solenoid, the external field is exactly zero everywhere, independent of distance.", "misconception": "Treating the solenoid like a dipole with distance-dependent field"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two long parallel wires separated by distance d carry currents I₁ and I₂ in the same direction. An Amperian loop enclosing both wires will give ∮B⃗·dl⃗ equal to:", "explanation": "By Ampere''s circuital law, ∮B⃗·dl⃗ = μ₀(I_enclosed). When both wires carry currents in the same direction and both are enclosed by the Amperian loop, I_enclosed = I₁ + I₂. Therefore ∮B⃗·dl⃗ = μ₀(I₁ + I₂).", "correct_answer": "D", "concept_tags": ["parallel-wires", "enclosed-current", "superposition"], "payload": {"question_id": "cuet-phy-mag-ampere-12", "subtopic": "Line integral of B", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀(I₁ − I₂)", "is_correct": false}, {"key": "B", "text": "μ₀I₁", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "μ₀(I₁ + I₂)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Subtraction would apply if the currents were in opposite directions. For same-direction currents, the enclosed current is I₁ + I₂.", "misconception": "Confusing same-direction with opposite-direction current addition"}, {"option_key": "B", "hint": "Both wires are enclosed by the loop, so both currents contribute. I_enclosed = I₁ + I₂, not just I₁.", "misconception": "Considering only one wire''s contribution"}, {"option_key": "C", "hint": "Zero would result if the currents cancelled (equal and opposite). Same-direction currents add up.", "misconception": "Thinking currents always cancel in a multi-wire setup"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A toroid has 1000 turns, mean radius 20 cm, and carries a current of 3 A. The magnetic field at the centre of the cross-section of the toroid is approximately:", "explanation": "For a toroid, B = μ₀NI/(2πR) = (4π × 10⁻⁷ × 1000 × 3)/(2π × 0.2) = (12π × 10⁻⁴)/(0.4π) = 12 × 10⁻⁴/0.4 = 30 × 10⁻⁴ = 3 × 10⁻³ T = 3 mT.", "correct_answer": "B", "concept_tags": ["toroid", "numerical", "ampere-law-application"], "payload": {"question_id": "cuet-phy-mag-ampere-13", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "1.5 × 10⁻³ T", "is_correct": false}, {"key": "B", "text": "3 × 10⁻³ T", "is_correct": true}, {"key": "C", "text": "6 × 10⁻³ T", "is_correct": false}, {"key": "D", "text": "3 × 10⁻⁴ T", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This is half the correct value. Check: μ₀NI/(2πR) = (4π × 10⁻⁷ × 3000)/(2π × 0.2) = 3 × 10⁻³ T.", "misconception": "Extra factor of 2 in the denominator"}, {"option_key": "C", "hint": "This is double the correct value. Ensure R = 20 cm = 0.2 m is used, not 0.1 m.", "misconception": "Using radius instead of diameter or vice versa"}, {"option_key": "D", "hint": "This is off by a factor of 10. Recheck the calculation carefully.", "misconception": "Error in powers of ten"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Ampere''s circuital law in its original form is not valid when:", "explanation": "The original Ampere''s circuital law (∮B⃗·dl⃗ = μ₀I_enc) is valid only for steady (time-independent) currents. When electric fields change with time, a displacement current term μ₀ε₀(dΦ_E/dt) must be added (Maxwell''s modification). This is a key limitation of the original law.", "correct_answer": "D", "concept_tags": ["limitations", "displacement-current", "maxwell-modification"], "payload": {"question_id": "cuet-phy-mag-ampere-14", "subtopic": "Limitations", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "The current is very large", "is_correct": false}, {"key": "B", "text": "The Amperian loop is very small", "is_correct": false}, {"key": "C", "text": "The wire is curved", "is_correct": false}, {"key": "D", "text": "The electric field is changing with time", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Ampere''s law has no restriction on the magnitude of current. It works for any steady current, large or small.", "misconception": "Thinking the law breaks down for large currents"}, {"option_key": "B", "hint": "The law holds for Amperian loops of any size. The loop size affects what current is enclosed, not the law''s validity.", "misconception": "Confusing loop size with validity"}, {"option_key": "C", "hint": "Ampere''s law applies to any current configuration, straight or curved, as long as the current is steady.", "misconception": "Thinking the law requires straight wires"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A long cylindrical conductor of radius R carries a uniformly distributed current I. Using Ampere''s circuital law, the magnetic field at a distance r (r < R) from the axis is:", "explanation": "For r < R, the Amperian loop of radius r encloses a fraction of the total current: I_enc = I(πr²/πR²) = Ir²/R². By Ampere''s law: B(2πr) = μ₀Ir²/R², giving B = μ₀Ir/(2πR²). The field increases linearly with r inside the conductor.", "correct_answer": "A", "concept_tags": ["cylindrical-conductor", "internal-field", "linear-variation"], "payload": {"question_id": "cuet-phy-mag-ampere-15", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "apply", "options": [{"key": "A", "text": "μ₀Ir/(2πR²)", "is_correct": true}, {"key": "B", "text": "μ₀I/(2πr)", "is_correct": false}, {"key": "C", "text": "μ₀IR/(2πr²)", "is_correct": false}, {"key": "D", "text": "μ₀I/(2πR)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This formula applies outside the conductor (r > R), where all current I is enclosed. Inside, only a fraction r²/R² of I is enclosed.", "misconception": "Using the external field formula for the interior region"}, {"option_key": "C", "hint": "This has incorrect powers of r and R. The enclosed current is proportional to r², and dividing by 2πr gives B ∝ r, not R/r².", "misconception": "Inverting the r and R dependence"}, {"option_key": "D", "hint": "This gives the field at the surface (r = R) and is a constant, but inside the conductor B varies linearly with r.", "misconception": "Taking r = R instead of keeping r as variable"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A coaxial cable has an inner conductor of radius a carrying current I and an outer conductor (hollow cylinder) of inner radius b and outer radius c carrying current I in the opposite direction. The magnetic field in the region a < r < b is:", "explanation": "In the region a < r < b (between the conductors), the Amperian loop of radius r encloses only the inner conductor''s current I. By Ampere''s law: B(2πr) = μ₀I, giving B = μ₀I/(2πr). The outer conductor''s current doesn''t contribute since it''s outside the Amperian loop.", "correct_answer": "C", "concept_tags": ["coaxial-cable", "ampere-law-application", "enclosed-current"], "payload": {"question_id": "cuet-phy-mag-ampere-16", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "μ₀I/(2πa)", "is_correct": false}, {"key": "C", "text": "μ₀I/(2πr)", "is_correct": true}, {"key": "D", "text": "μ₀2I/(2πr)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The field is zero only outside both conductors (r > c) where the net enclosed current is zero. Between the conductors, I_enc = I.", "misconception": "Thinking the field cancels everywhere due to opposite currents"}, {"option_key": "B", "hint": "The field depends on the distance r from the axis, not the inner conductor radius a. B varies as 1/r in this region.", "misconception": "Using the conductor radius instead of the field point distance"}, {"option_key": "D", "hint": "Only the inner conductor''s current I is enclosed, not 2I. The outer current lies outside the Amperian loop for a < r < b.", "misconception": "Adding both currents instead of using only the enclosed one"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An infinite hollow cylindrical conductor has inner radius a and outer radius b, carrying a uniformly distributed current I. The magnetic field at a distance r where a < r < b from the axis is:", "explanation": "The current is distributed in the annular region from a to b. For a < r < b, the enclosed current is I_enc = I × (r² − a²)/(b² − a²). By Ampere''s law: B(2πr) = μ₀I(r² − a²)/(b² − a²), giving B = μ₀I(r² − a²)/[2πr(b² − a²)].", "correct_answer": "D", "concept_tags": ["hollow-conductor", "partial-enclosed-current", "ampere-law"], "payload": {"question_id": "cuet-phy-mag-ampere-17", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "μ₀Ir/(2πb²)", "is_correct": false}, {"key": "B", "text": "μ₀I/(2πr)", "is_correct": false}, {"key": "C", "text": "μ₀I(r² − a²)/(2πr·b²)", "is_correct": false}, {"key": "D", "text": "μ₀I(r² − a²)/[2πr(b² − a²)]", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This formula is for a solid conductor of radius b. A hollow conductor has no current for r < a, so the area ratio is (r² − a²)/(b² − a²), not r²/b².", "misconception": "Treating hollow conductor as solid"}, {"option_key": "B", "hint": "This would be correct only outside the conductor (r > b). Inside the conductor wall, only a fraction of I is enclosed.", "misconception": "Using the total current formula inside the conductor"}, {"option_key": "C", "hint": "The denominator should be (b² − a²), not just b². The current-carrying area is π(b² − a²), not πb².", "misconception": "Incorrect area of the annular cross-section"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A solenoid has 2000 turns, length 40 cm, and carries 3 A. If it is bent into a toroid of mean radius R such that all turns are uniformly distributed, the magnetic field inside the toroid compared to that inside the original solenoid will be:", "explanation": "For the solenoid: B_sol = μ₀nI = μ₀(2000/0.4)(3) = μ₀(5000)(3) = 15000μ₀. For the toroid: B_tor = μ₀NI/(2πR). The length of the solenoid = circumference of toroid: 0.4 m = 2πR, so R = 0.4/(2π). Then B_tor = μ₀(2000)(3)/(2π × 0.4/(2π)) = μ₀ × 6000/0.4 = 15000μ₀. The field is the same because n = N/(2πR) and the solenoid length equals 2πR.", "correct_answer": "B", "concept_tags": ["solenoid-toroid-comparison", "conceptual", "ampere-law"], "payload": {"question_id": "cuet-phy-mag-ampere-18", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Greater in the toroid", "is_correct": false}, {"key": "B", "text": "The same at the mean radius", "is_correct": true}, {"key": "C", "text": "Less in the toroid", "is_correct": false}, {"key": "D", "text": "Cannot be compared without knowing R", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Since the solenoid length becomes 2πR, n = N/L is the same as N/(2πR), and B = μ₀nI is identical.", "misconception": "Thinking bending concentrates the field"}, {"option_key": "C", "hint": "The toroid doesn''t weaken the field. At the mean radius the field equals the solenoid field.", "misconception": "Thinking bending reduces field due to geometry change"}, {"option_key": "D", "hint": "R is determined by the solenoid length: 2πR = L = 0.4 m. No additional information is needed.", "misconception": "Not recognizing that the solenoid length fixes the toroid radius"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A long straight wire carries current I. An Amperian loop in the form of a square of side ''a'' is placed such that the wire passes through the centre of the square, perpendicular to its plane. The value of ∮B⃗·dl⃗ around this square loop is:", "explanation": "Ampere''s circuital law states ∮B⃗·dl⃗ = μ₀I_enclosed. The shape of the Amperian loop does not matter — it can be circular, square, or any closed curve. Since the wire carrying current I passes through the loop, I_enclosed = I, and ∮B⃗·dl⃗ = μ₀I regardless of the square shape.", "correct_answer": "C", "concept_tags": ["amperian-loop-shape", "line-integral", "loop-independence"], "payload": {"question_id": "cuet-phy-mag-ampere-19", "subtopic": "Amperian loop", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "μ₀I × 4a", "is_correct": false}, {"key": "B", "text": "μ₀I/(4a)", "is_correct": false}, {"key": "C", "text": "μ₀I", "is_correct": true}, {"key": "D", "text": "Cannot be determined as B is not constant on the square", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The perimeter 4a does not appear in the result. Ampere''s law gives ∮B⃗·dl⃗ = μ₀I regardless of loop shape or size.", "misconception": "Multiplying μ₀I by the perimeter"}, {"option_key": "B", "hint": "Division by the side length has no basis. The line integral equals μ₀I independent of loop dimensions.", "misconception": "Incorrectly dividing by a geometric factor"}, {"option_key": "D", "hint": "While B⃗ is not constant on the square loop (making it harder to find B), the line integral ∮B⃗·dl⃗ is still determined by Ampere''s law as μ₀I.", "misconception": "Confusing the ability to find B at each point with the value of the integral"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Inside a toroid of rectangular cross-section with inner radius a, outer radius b, N turns, and current I, the magnetic field varies as:", "explanation": "For a toroid, applying Ampere''s law with a circular loop of radius r (a < r < b): B(2πr) = μ₀NI, so B = μ₀NI/(2πr). The field varies inversely with r. It is strongest at the inner radius a and weakest at the outer radius b. The field is not uniform across the cross-section.", "correct_answer": "A", "concept_tags": ["toroid", "field-variation", "non-uniform-field"], "payload": {"question_id": "cuet-phy-mag-ampere-20", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "B ∝ 1/r, where r is the distance from the centre of the toroid", "is_correct": true}, {"key": "B", "text": "B is uniform throughout the cross-section", "is_correct": false}, {"key": "C", "text": "B ∝ r", "is_correct": false}, {"key": "D", "text": "B ∝ 1/r²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Unlike an ideal solenoid, the toroid''s field is not uniform. B = μ₀NI/(2πr) varies with the radial position r.", "misconception": "Treating toroid field as uniform like a solenoid"}, {"option_key": "C", "hint": "B ∝ r applies inside a solid conductor. In a toroid, all N turns are enclosed for any loop between a and b, giving B ∝ 1/r.", "misconception": "Confusing toroid with solid conductor field variation"}, {"option_key": "D", "hint": "The 1/r² dependence applies to point sources (dipoles at large distances). The line integral geometry gives B ∝ 1/r for a toroid.", "misconception": "Using inverse-square law instead of Ampere''s law result"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "easy", "question_text": "Assertion (A): Ampere''s circuital law can be used to easily find the magnetic field of an infinite straight current-carrying wire.\nReason (R): The magnetic field of an infinite straight wire has cylindrical symmetry, making B constant on a circular Amperian loop.", "explanation": "Both A and R are true. The cylindrical symmetry of the infinite wire ensures that B is constant in magnitude and tangential on any coaxial circular loop. This makes the integral ∮B⃗·dl⃗ = B(2πr) trivially solvable, which is exactly why Ampere''s law is useful here. R correctly explains A.", "correct_answer": "A", "concept_tags": ["assertion-reasoning", "symmetry", "infinite-wire"], "payload": {"question_id": "cuet-phy-mag-ampere-25", "subtopic": "Application to infinite wire", "topic_name": "Ampere''s Circuital Law", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The reason directly explains why Ampere''s law is easy to apply: cylindrical symmetry makes B constant on the loop, enabling simple integration.", "misconception": "Not connecting symmetry to ease of application"}, {"option_key": "C", "hint": "The reason is true — cylindrical symmetry does make B constant on circular loops concentric with the wire.", "misconception": "Denying the cylindrical symmetry of the wire''s field"}, {"option_key": "D", "hint": "The assertion is true — Ampere''s law is indeed a standard and easy method for finding B around an infinite wire.", "misconception": "Thinking Ampere''s law cannot be applied to find B of a straight wire"}]}}, {"chapter_id": "cuet-phy-magnetic-effects", "topic_id": "cuet-phy-mag-ampere", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The magnetic field at any point inside an ideal toroid in the empty space (not in the windings) is zero.\nReason (R): Ampere''s circuital law gives ∮B⃗·dl⃗ = 0 when the Amperian loop does not enclose any current.", "explanation": "A is false — the magnetic field inside a toroid (in the region of the windings, between the inner and outer radius) is non-zero: B = μ₀NI/(2πr). The field is zero only in the central hollow region (r < inner radius) and outside (r > outer radius). R is true — Ampere''s law does give zero when no current is enclosed. Since A is false and R is true, the answer is D.", "correct_answer": "D", "concept_tags": ["assertion-reasoning", "toroid", "field-regions"], "payload": {"question_id": "cuet-phy-mag-ampere-26", "subtopic": "Application to toroid", "topic_name": "Ampere''s Circuital Law", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are true and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The assertion is incorrectly stated. Inside the toroid (within the windings region), B ≠ 0. The field is zero only in the central hollow and outside.", "misconception": "Confusing the central hollow of the toroid with the winding region"}, {"option_key": "B", "hint": "Since A is false (field inside the winding region is non-zero), this option is incorrect.", "misconception": "Not correctly identifying the regions of a toroid"}, {"option_key": "C", "hint": "The assertion is false (as explained above), and the reason is true (Ampere''s law indeed gives zero for loops with no enclosed current).", "misconception": "Incorrectly evaluating the truth of A and R"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

